{"content":"import React from 'react';
import {
  Home as HomeIcon, Search, LayoutDashboard, Activity, Sparkles,
  BookOpen, Fuel, Share2, Users, FileText, Bell, UserCircle, BarChart3,
  Link2, Code2
} from 'lucide-react';
import { useTranslation } from '../i18n';

interface SidebarProps {
  currentView: string;
  navigateTo: (view: string) => void;
  isSidebarCollapsed: boolean;
  isMobileMenuOpen: boolean;
  setIsMobileMenuOpen: (v: boolean) => void;
}

const NavItem = ({ view, label, icon: Icon, onClick, active, collapsed, currentView, navigateTo }: {
  view?: string;
  label: string;
  icon: React.ElementType;
  onClick?: () => void;
  active?: boolean;
  collapsed?: boolean;
  currentView: string;
  navigateTo: (view: string) => void;
}) => {
  const handleClick = onClick ? onClick : () => view && navigateTo(view);
  const isActive = active !== undefined ? active : (view && currentView === view);

  if (collapsed) {
    return (
      <div className="relative group">
        <button
          onClick={handleClick}
          className={`w-full flex items-center justify-center py-2.5 rounded-xl transition-all duration-200 ${
            isActive
              ? 'bg-gradient-to-r from-purple-600 to-violet-600 text-white shadow-lg shadow-purple-900/30'
              : 'text-gray-400 hover:text-white hover:bg-white/[0.06]'
          }`}
        >
          <Icon size={18} className={isActive ? "text-white" : "text-gray-500 group-hover:text-gray-300"} />
        </button>
        <div className="absolute left-full top-1/2 -translate-y-1/2 ml-3 px-3 py-1.5 bg-[#1a1d21] border border-white/[0.1] rounded-lg shadow-xl text-xs font-medium text-white whitespace-nowrap opacity-0 pointer-events-none group-hover:opacity-100 transition-opacity duration-200 z-50">
          {label}
          <div className="absolute right-full top-1/2 -translate-y-1/2 w-0 h-0 border-t-[5px] border-t-transparent border-b-[5px] border-b-transparent border-r-[5px] border-r-[#1a1d21]" />
        </div>
      </div>
    );
  }

  return (
    <button
      onClick={handleClick}
      className={`relative w-full flex items-center gap-3 px-3.5 py-2.5 rounded-xl text-[13.5px] transition-all duration-200 group font-sans overflow-hidden ${
        isActive
          ? 'bg-gradient-to-r from-purple-600 to-violet-600 text-white font-semibold shadow-lg shadow-purple-900/30'
          : 'text-gray-400 hover:text-white hover:bg-white/[0.06] font-medium'
      }`}
    >
      {/* Animated active indicator bar */}
      <div className={`absolute left-0 top-1/2 -translate-y-1/2 w-[3px] rounded-full bg-white transition-all duration-300 ${isActive ? 'h-5 opacity-100' : 'h-0 opacity-0'}`} />
      <Icon size={17} className={`shrink-0 ${isActive ? "text-white" : "text-gray-500 group-hover:text-gray-300"}`} />
      <span className="truncate transition-opacity duration-200">{label}</span>
    </button>
  );
};

const Sidebar: React.FC<SidebarProps> = ({
  currentView,
  navigateTo,
  isSidebarCollapsed,
  isMobileMenuOpen,
  setIsMobileMenuOpen,
}) => {
  const { t } = useTranslation();

  const navItemProps = { currentView, navigateTo };

  return (
    <>
      {/* Mobile overlay */}
      <div
        className={`md:hidden fixed inset-0 z-40 bg-black/70 backdrop-blur-sm transition-opacity duration-300 ${
          isMobileMenuOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'
        }`}
        onClick={() => setIsMobileMenuOpen(false)}
      />
      {/* Mobile sidebar */}
      <aside
        id="mobile-sidebar-menu"
        className={`md:hidden fixed top-0 left-0 bottom-0 z-50 w-[84%] max-w-[320px] bg-[#0e0e18] border-r border-white/[0.08] shadow-2xl shadow-black/50 transform transition-transform duration-300 ease-out ${
          isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'
        }`}
      >
        <div className="h-full flex flex-col pt-20 pb-6 px-4 overflow-y-auto">
          <div className="bg-[#13131d]/80 border border-white/[0.06] rounded-2xl p-3 space-y-1">
            <NavItem label={t.nav.home} icon={HomeIcon} view="home" {...navItemProps} />
            <NavItem label={t.nav.newAudit} icon={Search} view="analyze" {...navItemProps} />
            <NavItem label={t.nav.dashboard} icon={LayoutDashboard} view="dashboard" {...navItemProps} />
            <NavItem label={t.nav.monitoringAEO} icon={Activity} view="projects" active={['projects', 'results'].includes(currentView)} {...navItemProps} />
            <NavItem label={t.nav.generativeTools} icon={Sparkles} view="generative-tools" active={['generative-tools', 'smc-studio', 'source-of-truth', 'schema-org', 'robots-txt', 'content-writer', 'reputation', 'bot-tracking', 'blog-optimizer', 'ai-response-layer', 'llms-txt', 'answer-first-audit', 'ai-citation-simulator', 'eeat-builder'].includes(currentView)} {...navItemProps} />
            <NavItem label={t.nav.indexedDirectory} icon={BookOpen} view="directory" active={['directory', 'directory-entity'].includes(currentView)} {...navItemProps} />
            <NavItem label="API Developer" icon={Code2} view="api-developer" {...navItemProps} />
            <NavItem label="Intégrations" icon={Link2} view="integrations" {...navItemProps} />
            <NavItem label={t.nav.gtoGas} icon={Fuel} view="recharge" {...navItemProps} />
            <NavItem label={t.nav.affiliation} icon={Share2} view="affiliation" {...navItemProps} />
            <NavItem label={t.nav.baseClients} icon={Users} view="clients" {...navItemProps} />
            <NavItem label={t.nav.missionOrders} icon={FileText} view="mission-orders" {...navItemProps} />
            <NavItem label={t.nav.alertsAEO} icon={Bell} view="alerts" {...navItemProps} />

            <div className="my-4 border-t border-white/[0.08] mx-4"></div>

            <NavItem label={t.nav.accountPlan} icon={UserCircle} view="account" {...navItemProps} />
          </div>
        </div>
      </aside>

      {/* Desktop sidebar */}
      <aside className={`hidden md:flex flex-col py-4 sticky top-14 h-[calc(100vh-3.5rem)] overflow-y-auto shrink-0 transition-[width,padding] duration-300 ease-in-out ${
        isSidebarCollapsed ? 'w-[68px] px-2' : 'w-64 px-3'
      }`}>
        <div className={`bg-[#13131d]/80 border border-white/[0.06] rounded-2xl shadow-lg overflow-y-auto custom-scrollbar ${
          isSidebarCollapsed ? 'p-1.5 space-y-0.5' : 'p-3 space-y-1'
        }`}>
           {/* PRINCIPAL */}
           {!isSidebarCollapsed && <div className="px-4 pt-2 pb-1.5"><span className="text-[10px] font-bold text-gray-600 uppercase tracking-wider">Principal</span></div>}
           {isSidebarCollapsed && <div className="my-1" />}
           <NavItem label={t.nav.home} icon={HomeIcon} view="home" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.newAudit} icon={Search} view="analyze" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.dashboard} icon={LayoutDashboard} view="dashboard" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label="Monitoring IA" icon={BarChart3} view="ai-monitoring" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.monitoringAEO} icon={Activity} view="projects" active={['projects', 'results'].includes(currentView)} collapsed={isSidebarCollapsed} {...navItemProps} />

           {/* OUTILS */}
           {!isSidebarCollapsed && <div className="px-4 pt-5 pb-1.5"><span className="text-[10px] font-bold text-gray-600 uppercase tracking-wider">Outils</span></div>}
           {isSidebarCollapsed && <div className="my-2 mx-3 border-t border-white/[0.06]" />}
           <NavItem label={t.nav.generativeTools} icon={Sparkles} view="generative-tools" active={['generative-tools', 'smc-studio', 'source-of-truth', 'schema-org', 'robots-txt', 'content-writer', 'reputation', 'bot-tracking', 'blog-optimizer', 'ai-response-layer', 'llms-txt', 'answer-first-audit', 'ai-citation-simulator', 'eeat-builder'].includes(currentView)} collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.indexedDirectory} icon={BookOpen} view="directory" active={['directory', 'directory-entity'].includes(currentView)} collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label="API Developer" icon={Code2} view="api-developer" collapsed={isSidebarCollapsed} {...navItemProps} />

           {/* GESTION */}
           {!isSidebarCollapsed && <div className="px-4 pt-5 pb-1.5"><span className="text-[10px] font-bold text-gray-600 uppercase tracking-wider">Gestion</span></div>}
           {isSidebarCollapsed && <div className="my-2 mx-3 border-t border-white/[0.06]" />}
           <NavItem label="Intégrations" icon={Link2} view="integrations" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.gtoGas} icon={Fuel} view="recharge" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.affiliation} icon={Share2} view="affiliation" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.baseClients} icon={Users} view="clients" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.missionOrders} icon={FileText} view="mission-orders" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.alertsAEO} icon={Bell} view="alerts" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.accountPlan} icon={UserCircle} view="account" collapsed={isSidebarCollapsed} {...navItemProps} />
        </div>
      </aside>
    </>
  );
};

export default Sidebar;
"}

{"content":"import React from 'react';
import { PenTool, FileText, Code, FileCode, Search, Sparkles, AlertTriangle, Feather, Shield, Bot, BookOpen, Layers, ClipboardList, Target, MessageCircle, Trophy, Radar, Code2 } from 'lucide-react';
import { useTranslation } from '../i18n';

interface GenerativeToolsProps {
  onNavigate: (view: any) => void;
}

interface ToolCardProps {
  icon: React.ElementType;
  label: string;
  desc: string;
  color: string;
  bg: string;
  onClick: () => void;
}

const ToolCard: React.FC<ToolCardProps> = ({ icon: Icon, label, desc, color, bg, onClick }) => (
  <button
    onClick={onClick}
    className="ninja-card p-8 flex flex-col items-center justify-center gap-6 hover:bg-white/[0.04] transition-all duration-300 hover:-translate-y-2 hover:shadow-lg hover:shadow-purple-900/10 group h-full"
  >
    <div className={`relative p-5 rounded-2xl ${bg} group-hover:scale-110 transition-all duration-300`}>
      <Icon size={48} className={`${color} group-hover:drop-shadow-[0_0_8px_rgba(168,85,247,0.4)] transition-all duration-300`} />
      <div className="absolute inset-0 rounded-2xl bg-purple-500/0 group-hover:bg-purple-500/5 transition-all duration-300" />
    </div>
    <div className="text-center space-y-2">
      <span className="block text-xl font-bold text-gray-200 group-hover:text-white transition-colors duration-200">{label}</span>
      <span className="block text-sm text-gray-500 group-hover:text-gray-400 transition-colors duration-200">{desc}</span>
    </div>
  </button>
);

const GenerativeTools: React.FC<GenerativeToolsProps> = ({ onNavigate }) => {
  const { t } = useTranslation();

  const tools = [
    { id: 'smc-studio', label: t.generativeTools.smcStudio, icon: PenTool, color: 'text-purple-400', bg: 'bg-purple-500/10', desc: t.generativeTools.smcStudioDesc },
    { id: 'content-writer', label: t.generativeTools.contentWriter, icon: Feather, color: 'text-violet-400', bg: 'bg-violet-500/10', desc: t.generativeTools.contentWriterDesc },
    { id: 'reputation', label: t.generativeTools.reputation, icon: Shield, color: 'text-purple-400', bg: 'bg-purple-500/10', desc: t.generativeTools.reputationDesc },
    { id: 'source-of-truth', label: t.generativeTools.sourceOfTruth, icon: FileText, color: 'text-purple-400', bg: 'bg-purple-500/10', desc: t.generativeTools.sourceOfTruthDesc },
    { id: 'schema-org', label: t.generativeTools.schemaOrg, icon: Code, color: 'text-blue-400', bg: 'bg-blue-500/10', desc: t.generativeTools.schemaOrgDesc },
    { id: 'robots-txt', label: t.generativeTools.robotsTxt, icon: FileCode, color: 'text-purple-300', bg: 'bg-purple-500/10', desc: t.generativeTools.robotsTxtDesc },
    { id: 'bot-tracking', label: t.generativeTools.botTracking || 'Suivi Bots IA', icon: Bot, color: 'text-cyan-400', bg: 'bg-cyan-500/10', desc: t.generativeTools.botTrackingDesc || 'Activation & suivi des crawlers' },
    { id: 'blog-optimizer', label: t.generativeTools.blogOptimizer || 'Blog Optimiser', icon: BookOpen, color: 'text-pink-400', bg: 'bg-pink-500/10', desc: t.generativeTools.blogOptimizerDesc || 'Architecture & rédaction blog AEO' },
    { id: 'ai-response-layer', label: 'AI Response Layer', icon: Layers, color: 'text-emerald-400', bg: 'bg-emerald-500/10', desc: 'Hub, Query Pages, Catalogue & Sitemap IA' },
    { id: 'llms-txt', label: 'Générateur llms.txt', icon: ClipboardList, color: 'text-amber-400', bg: 'bg-amber-500/10', desc: 'Fichier llms.txt pour guider les IA sur votre marque' },
    { id: 'answer-first-audit', label: 'Audit Answer-First', icon: Target, color: 'text-rose-400', bg: 'bg-rose-500/10', desc: 'Score de citabilité IA sur 6 critères AEO' },
    { id: 'ai-citation-simulator', label: 'Simulateur Citation IA', icon: MessageCircle, color: 'text-sky-400', bg: 'bg-sky-500/10', desc: 'Simulez les réponses ChatGPT, Claude, Perplexity, Gemini & AI Overviews' },
    { id: 'eeat-builder', label: 'E-E-A-T Builder', icon: Trophy, color: 'text-yellow-400', bg: 'bg-yellow-500/10', desc: 'Bios auteur, About Page, Trust Signals & Audit E-E-A-T' },
    { id: 'ai-monitoring', label: 'Monitoring IA', icon: Radar, color: 'text-cyan-400', bg: 'bg-cyan-500/10', desc: 'Tracker vos citations sur ChatGPT, Claude, Perplexity, Gemini & AI Overviews' },
    { id: 'api-developer', label: 'API Developer Hub', icon: Code2, color: 'text-indigo-400', bg: 'bg-indigo-500/10', desc: 'Documentation, clés API, webhooks & SDK' },
  ];

  return (
    <div className="w-full px-6 py-8 animate-in fade-in duration-500">

      {/* Header style Dashboard Pro */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-6">
        <div className="flex items-center gap-4">
          <h1 className="text-3xl font-bold text-white">{t.generativeTools.title.split(' ').slice(0, -1).join(' ')} <span className="gradient-text">{t.generativeTools.title.split(' ').slice(-1)}</span></h1>
          <span className="bg-purple-500/10 text-purple-400 text-xs font-bold px-3 py-1 rounded-full border border-primary/20 flex items-center gap-1">
            <Sparkles size={12} /> {t.generativeTools.suitePro}
          </span>
        </div>

        <div className="flex items-center gap-4 w-full md:w-auto">
          <div className="relative flex-1 md:flex-none">
            <input
              type="text"
              placeholder={t.generativeTools.searchPlaceholder}
              className="bg-[#111111] border border-white/[0.08] rounded-2xl py-2.5 pl-4 pr-10 text-sm text-gray-300 focus:outline-none focus:border-purple-500/50 w-full md:w-80 transition-all"
            />
            <Search size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" />
          </div>
        </div>
      </div>

      {/* Grid des Outils */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 mb-12">
        {tools.map((tool) => (
            <ToolCard
                key={tool.id}
                icon={tool.icon}
                label={tool.label}
                desc={tool.desc}
                color={tool.color}
                bg={tool.bg}
                onClick={() => onNavigate(tool.id)}
            />
        ))}
      </div>

      {/* Section Explicative */}
      <div className="ninja-card p-8">
        <div className="flex items-center gap-3 mb-6">
            <div className="p-2 bg-purple-500/10 rounded-full">
                <AlertTriangle size={20} className="text-yellow-400" />
            </div>
            <h3 className="text-xl font-bold text-white">{t.generativeTools.whyUse}</h3>
        </div>

        <div className="grid md:grid-cols-3 gap-8">
            <div className="space-y-3">
                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.structuredContent}</h4>
                <p className="text-sm text-gray-500 leading-relaxed">
                    {t.generativeTools.structuredContentDesc}
                </p>
            </div>
            <div className="space-y-3">
                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.technicalData}</h4>
                <p className="text-sm text-gray-500 leading-relaxed">
                    {t.generativeTools.technicalDataDesc}
                </p>
            </div>
            <div className="space-y-3">
                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.sourceAuthority}</h4>
                <p className="text-sm text-gray-500 leading-relaxed">
                    {t.generativeTools.sourceAuthorityDesc}
                </p>
            </div>
        </div>
      </div>

    </div>
  );
};

export default GenerativeTools;
"}

{"content":"import React, { useState } from 'react';
import { User, SMCContent } from '../types';
import { smcService } from '../services/smc';
import { ArrowLeft, FileText, HelpCircle, PenTool, Sparkles, Copy, Download, Check, Loader2, Layout, MessageSquare, BookOpen, Library, Clock, AlignLeft, Link as LinkIcon, Bot, Archive, ChevronRight, Award, Globe, ArrowRight, Eye } from 'lucide-react';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
  library: SMCContent[];
  onAddToLibrary: (item: SMCContent) => void;
  onNavigateToPublisher?: (data: { topic: string, url: string, brief: string }) => void;
  onNavigateToDirectory?: () => void;
}

type ToolType = 'home' | 'fiche' | 'faq' | 'article';
type Tab = 'studio' | 'library';

const SMCStudio: React.FC<Props> = ({ onBack, user, onDeductCredits, library, onAddToLibrary, onNavigateToPublisher, onNavigateToDirectory }) => {
  const [activeTab, setActiveTab] = useState<Tab>('studio');
  const [currentTool, setCurrentTool] = useState<ToolType>('home');
  const [result, setResult] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [copied, setCopied] = useState(false);

  // --- States pour l'outil Article (Flux Blog Optimizer) ---
  const [articleStep, setArticleStep] = useState<'brief' | 'writing' | 'done'>('brief');
  const [briefContent, setBriefContent] = useState('');

  // Form States
  const [ficheData, setFicheData] = useState({ name: '', features: '' });
  const [faqData, setFaqData] = useState({ topic: '', context: '' });
  const [articleData, setArticleData] = useState({ title: '', url: '', tone: 'Professionnel' }); // URL & Tone used for Brief gen

  const COSTS = {
    fiche: 1,
    faq: 1,
    brief: 1, // Brief d'article
    article: 3 // Rédaction complète
  };

  const handleCopy = (content: string) => {
    navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = (filename: string, content: string) => {
    const blob = new Blob([content], { type: 'text/markdown' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleNavigateToPublisherAction = () => {
    if (onNavigateToPublisher) {
        onNavigateToPublisher({
            topic: articleData.title,
            url: articleData.url,
            brief: briefContent // Le PublisherRequest se base sur le brief
        });
    }
  };

  const handleRestoreFromLibrary = (item: SMCContent) => {
    // 1. Déterminer l'outil
    let tool: ToolType = 'home';
    if (item.type === 'fiche') tool = 'fiche';
    else if (item.type === 'faq') tool = 'faq';
    else if (item.type === 'article' || item.type === 'brief') tool = 'article';

    setCurrentTool(tool);

    // 2. Restaurer le contenu et l'état
    if (item.type === 'article') {
        setResult(item.content);
        setArticleStep('done');
        // Tentative de récupération du titre depuis "Article: Titre - Date"
        const titleClean = item.title.split(' - ')[0].replace('Article: ', '').trim();
        setArticleData(prev => ({ ...prev, title: titleClean }));
        // Si possible, on pourrait essayer de retrouver le brief parent via meta, mais ici on affiche juste le résultat
    } else if (item.type === 'brief') {
        setBriefContent(item.content);
        setArticleStep('writing');
        const titleClean = item.title.split(' - ')[0].replace('Brief: ', '').trim();
        setArticleData(prev => ({ ...prev, title: titleClean }));
    } else {
        setResult(item.content);
        // Restauration contextuelle basique pour les formulaires
        if (item.type === 'fiche') {
             const nameClean = item.title.split(' - ')[0].replace('Fiche: ', '').trim();
             setFicheData(prev => ({ ...prev, name: nameClean }));
        }
        if (item.type === 'faq') {
             const topicClean = item.title.split(' - ')[0].replace('FAQ: ', '').trim();
             setFaqData(prev => ({ ...prev, topic: topicClean }));
        }
    }

    // 3. Basculer vers l'onglet Studio
    setActiveTab('studio');
  };

  // Generic generator for simple tools (Fiche, FAQ)
  const runSimpleGeneration = async (type: 'fiche' | 'faq', cost: number, generator: () => Promise<string>, titlePrefix: string) => {
    if (onDeductCredits(cost)) {
      setIsGenerating(true);
      setResult('');
      try {
        const content = await generator();
        setResult(content);

        // Save to Library
        const newItem: SMCContent = {
            id: `smc_${Date.now()}`,
            type,
            title: `${titlePrefix} - ${new Date().toLocaleTimeString()}`,
            content,
            timestamp: new Date().toISOString()
        };
        onAddToLibrary(newItem);

      } catch (e) {
        console.error(e);
        alert("Une erreur est survenue.");
      } finally {
        setIsGenerating(false);
      }
    }
  };

  // --- Article Generation Logic (2 Steps) ---

  const handleGenerateBrief = async () => {
    if (!articleData.title && !articleData.url) {
        alert("Sujet ou URL requis.");
        return;
    }

    if (onDeductCredits(COSTS.brief)) {
        setIsGenerating(true);
        try {
            const brief = await smcService.generateBrief(articleData.title, articleData.url);
            setBriefContent(brief);
            setArticleStep('writing'); // Move to step 2

            // Save Brief to Library
            onAddToLibrary({
                id: `brief_${Date.now()}`,
                type: 'brief',
                title: `Brief: ${articleData.title || 'Architecture Article'}`,
                content: brief,
                timestamp: new Date().toISOString()
            });

        } catch (e) {
            console.error(e);
            alert("Erreur lors du brief.");
        } finally {
            setIsGenerating(false);
        }
    }
  };

  const handleWriteFullArticle = async () => {
    if (onDeductCredits(COSTS.article)) {
        setIsGenerating(true);
        try {
            const article = await smcService.generateFullArticle(briefContent, articleData.title);
            setResult(article);
            setArticleStep('done'); // Move to step 3

            // Save Article to Library
            onAddToLibrary({
                id: `art_${Date.now()}`,
                type: 'article',
                title: `Article: ${articleData.title || 'Rédaction Complète'}`,
                content: article,
                timestamp: new Date().toISOString(),
                meta: { briefId: `brief_${Date.now()}` } // Link to brief loosely
            });

        } catch (e) {
            console.error(e);
            alert("Erreur lors de la rédaction.");
        } finally {
            setIsGenerating(false);
        }
    }
  };

  const renderHome = () => (
