            className="flex items-center text-gray-400 hover:text-white transition-colors"
        >
            <ArrowLeft size={18} className="mr-2" /> 
            {activeTab === 'studio' && currentTool !== 'home' ? 'Retour au studio' : 'Retour'}
        </button>

        {/* Tabs Switcher */}
        <div className="flex bg-[#111111] p-1 rounded-full border border-white/[0.08]">
            <button
                onClick={() => setActiveTab('studio')}
                className={`px-6 py-2 rounded-full text-sm font-medium transition-all flex items-center gap-2 ${activeTab === 'studio' ? 'btn-gradient !py-2 !px-6' : 'text-gray-500 hover:text-gray-300'}`}
            >
                <Sparkles size={16} /> Studio
            </button>
            <button
                onClick={() => setActiveTab('library')}
                className={`px-6 py-2 rounded-full text-sm font-medium transition-all flex items-center gap-2 ${activeTab === 'library' ? 'btn-gradient !py-2 !px-6' : 'text-gray-500 hover:text-gray-300'}`}
            >
                <Library size={16} /> Bibliothèque <span className="bg-white/10 px-1.5 py-0.5 rounded-full text-[10px]">{library.length}</span>
            </button>
        </div>
      </div>

      {activeTab === 'studio' ? (currentTool === 'home' ? renderHome() : renderTool()) : renderLibrary()}
    </div>
  );
};

export default SMCStudio;"}

{"content":"import React, { useState, useEffect } from 'react';
import { AnalysisResult, User, SMCContent } from '../types';
import { generateJsonLd, SchemaInput } from '../services/schema_service';
import { ArrowLeft, Code, Download, Copy, Check, ShieldCheck, Globe, Share2, Building2, Phone, Mail, Image as ImageIcon, ExternalLink, RefreshCw, Zap, Archive, Eye } from 'lucide-react';

interface Props {
  onBack: () => void;
  history: AnalysisResult[];
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
  savedFiles: SMCContent[];
  onSaveFile: (item: SMCContent) => void;
}

const SchemaOrg: React.FC<Props> = ({ onBack, history, user, onDeductCredits, savedFiles, onSaveFile }) => {
  const [copied, setCopied] = useState(false);
  const [formData, setFormData] = useState<SchemaInput>({
    name: '',
    url: '',
    logoUrl: '',
    description: '',
    socialProfiles: ['', '', ''],
    contactPhone: '',
    contactEmail: '',
    alternateName: ''
  });

  const [jsonOutput, setJsonOutput] = useState('');
  const [isGenerated, setIsGenerated] = useState(false);

  // Pré-remplissage basé sur l'historique
  useEffect(() => {
    if (history.length > 0) {
      const latest = history[0];
      const urlObj = new URL(latest.url);
      const hostname = urlObj.hostname;
      const name = hostname.replace('www.', '').split('.')[0];
      const formattedName = name.charAt(0).toUpperCase() + name.slice(1);

      setFormData(prev => ({
        ...prev,
        name: formattedName,
        url: urlObj.origin,
        logoUrl: `${urlObj.origin}/logo.png`,
        description: `Site officiel de ${formattedName}.`,
        contactEmail: `contact@${hostname}`
      }));
    }
  }, [history]);

  // Régénération automatique à chaque changement du formulaire
  useEffect(() => {
    if (isGenerated) {
        setJsonOutput(generateJsonLd(formData));
    }
  }, [formData, isGenerated]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSocialChange = (index: number, value: string) => {
    const newSocials = [...formData.socialProfiles];
    newSocials[index] = value;
    setFormData({ ...formData, socialProfiles: newSocials });
  };

  const handleGenerate = () => {
    if (onDeductCredits(5)) {
        const output = generateJsonLd(formData);
        setJsonOutput(output);
        setIsGenerated(true);

        // Sauvegarde dans l'historique
        onSaveFile({
            id: `schema_${Date.now()}`,
            type: 'fiche', // Using Generic type
            title: `Schema Organization - ${formData.name}`,
            content: output,
            timestamp: new Date().toISOString()
        });
    }
  };

  const handleCopy = (content?: string) => {
    navigator.clipboard.writeText(content || jsonOutput);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = (filename?: string, content?: string) => {
    const blob = new Blob([content || jsonOutput], { type: 'application/ld+json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename || 'schema.jsonld';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleRestore = (content: string) => {
      // Pour une restauration complète, il faudrait parser le JSON pour remplir le formulaire
      // Ici on restaure juste le code de sortie pour la visualisation
      setJsonOutput(content);
      setIsGenerated(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="w-full px-4 py-10 animate-in fade-in duration-500 min-h-screen">
      <button onClick={onBack} className="flex items-center text-gray-500 hover:text-white mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" /> Retour
      </button>

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
        <div>
          <h1 className="text-3xl font-sans font-bold text-white mb-2 flex items-center gap-3">
             <div className="w-10 h-10 rounded-2xl bg-purple-500/20 flex items-center justify-center text-purple-400 border border-purple-500/30">
              <Code size={24} />
            </div>
            Générateur Schema.org
          </h1>
          <p className="text-gray-500">Créez le JSON-LD "Organization" pour connecter votre marque au Knowledge Graph de Google et des IA.</p>
        </div>

        {user && (
            <div className="bg-white/[0.04] border border-white/[0.08] px-4 py-2 rounded-2xl text-sm text-gray-300">
                Solde : <span className="font-bold text-white">{user.credits}</span> Gas
            </div>
        )}
      </div>

      <div className="grid lg:grid-cols-12 gap-8">

        {/* Formulaire Gauche */}
        <div className="lg:col-span-5 space-y-6">
            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08]">
                <h3 className="font-bold text-white mb-4 flex items-center gap-2">
                    <Building2 size={18} className="text-purple-400" /> Identité de l'Organisation
                </h3>

                <div className="space-y-4">
                    <div>
                        <label className="block text-xs font-medium text-gray-500 mb-1">Nom de l'organisation</label>
                        <input 
                            type="text" 
                            name="name"
                            value={formData.name}
                            onChange={handleInputChange}
                            className="w-full bg-black/40 border border-white/[0.08] rounded-xl px-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                            placeholder="Ex: CitedBy Corp"
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-medium text-gray-500 mb-1">Nom alternatif (Optionnel)</label>
                        <input 
                            type="text" 
                            name="alternateName"
                            value={formData.alternateName}
                            onChange={handleInputChange}
                            className="w-full bg-black/40 border border-white/[0.08] rounded-xl px-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                            placeholder="Ex: CBC"
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-medium text-gray-500 mb-1">URL du site Web</label>
                        <div className="relative">
                            <Globe size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
                            <input 
                                type="url" 
                                name="url"
                                value={formData.url}
                                onChange={handleInputChange}
                                className="w-full bg-black/40 border border-white/[0.08] rounded-xl pl-9 pr-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                                placeholder="https://..."
                            />
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs font-medium text-gray-500 mb-1">URL du Logo</label>
                        <div className="relative">
                            <ImageIcon size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
                            <input 
                                type="url" 
                                name="logoUrl"
                                value={formData.logoUrl}
                                onChange={handleInputChange}
                                className="w-full bg-black/40 border border-white/[0.08] rounded-xl pl-9 pr-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                                placeholder="https://.../logo.png"
                            />
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs font-medium text-gray-500 mb-1">Description courte</label>
                        <textarea 
                            name="description"
                            value={formData.description}
                            onChange={handleInputChange}
                            rows={3}
                            className="w-full bg-black/40 border border-white/[0.08] rounded-xl px-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none resize-none"
                            placeholder="Description pour le Knowledge Graph..."
                        />
                    </div>
                </div>
            </div>

            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08]">
                <h3 className="font-bold text-white mb-4 flex items-center gap-2">
                    <Share2 size={18} className="text-purple-400" /> Réseaux & Contact
                </h3>

                <div className="space-y-4">
                    <div>
                        <label className="block text-xs font-medium text-gray-500 mb-1">Profils Sociaux (sameAs)</label>
                        <div className="space-y-2">
                            {formData.socialProfiles.map((url, idx) => (
                                <input 
                                    key={idx}
                                    type="url" 
                                    value={url}
                                    onChange={(e) => handleSocialChange(idx, e.target.value)}
                                    className="w-full bg-black/40 border border-white/[0.08] rounded-xl px-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                                    placeholder={`URL Profil social ${idx + 1}`}
                                />
                            ))}
                        </div>
                        <p className="text-[10px] text-gray-500 mt-1">Essentiel pour la désambiguïsation de l'entité.</p>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-xs font-medium text-gray-500 mb-1">Téléphone</label>
                            <div className="relative">
                                <Phone size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
                                <input 
                                    type="tel" 
                                    name="contactPhone"
                                    value={formData.contactPhone}
                                    onChange={handleInputChange}
                                    className="w-full bg-black/40 border border-white/[0.08] rounded-xl pl-9 pr-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                                    placeholder="+33..."
                                />
                            </div>
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-gray-500 mb-1">Email</label>
                            <div className="relative">
                                <Mail size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
                                <input 
                                    type="email" 
                                    name="contactEmail"
                                    value={formData.contactEmail}
                                    onChange={handleInputChange}
                                    className="w-full bg-black/40 border border-white/[0.08] rounded-xl pl-9 pr-3 py-2 text-sm text-white focus:border-purple-500/50 outline-none"
                                    placeholder="contact@..."
                                />
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <button 
                onClick={handleGenerate}
                className="w-full py-4 bg-purple-600 hover:bg-purple-700 text-white font-bold rounded-2xl transition-all shadow-lg shadow-purple-500/20 flex items-center justify-center gap-2"
            >
                {isGenerated ? <RefreshCw size={18} /> : <Zap size={18} />}
                {isGenerated ? 'Mettre à jour le code' : 'Générer le code JSON-LD (-5 crédits)'}
            </button>
        </div>

        {/* Output Droite */}
        <div className="lg:col-span-7 flex flex-col gap-6">
            <div className="bg-[#0f1115] border border-white/[0.08] rounded-2xl flex flex-col shadow-2xl overflow-hidden h-full min-h-[500px]">
                <div className="p-4 border-b border-white/[0.08] flex items-center justify-between bg-white/[0.04]">
                    <div className="flex items-center gap-2">
                        <span className="text-sm font-bold text-white flex items-center gap-2">
                            <Code size={16} className="text-purple-400" />
                            {'<script type="application/ld+json">'}
                        </span>
                    </div>
                    <div className="flex gap-2">
                        <button onClick={() => handleCopy()} disabled={!isGenerated} className="flex items-center gap-2 px-3 py-1.5 bg-white/[0.04] hover:bg-white/[0.08] rounded-full text-xs font-medium text-white border border-white/[0.08] transition-colors disabled:opacity-50">
                            {copied ? <Check size={14} className="text-purple-300" /> : <Copy size={14} />}
                            {copied ? 'Copié' : 'Copier'}
                        </button>
                        <button onClick={() => handleDownload()} disabled={!isGenerated} className="flex items-center gap-2 px-3 py-1.5 bg-gradient-to-r from-purple-500 to-violet-600 text-white hover:from-purple-600 hover:to-violet-700 rounded-full text-xs font-bold transition-colors disabled:opacity-50">
                            <Download size={14} /> Télécharger
                        </button>
                    </div>
                </div>

                <div className="relative bg-[#000000] p-6 flex-1 group">
                    {isGenerated ? (
                        <pre className="font-mono text-sm text-purple-100/90 whitespace-pre-wrap leading-relaxed selection:bg-purple-500/30 overflow-auto h-full max-h-[600px]">
                            {jsonOutput}
                        </pre>
                    ) : (
                        <div className="absolute inset-0 flex flex-col items-center justify-center text-gray-500 opacity-50">
                            <Code size={64} className="mb-4" />
                            <p>Remplissez le formulaire pour générer le code.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Implementation Guide */}
            <div className="bg-white/[0.04] rounded-2xl border border-white/[0.08] p-6">
                <h3 className="font-bold text-white mb-4 flex items-center gap-2">
                    <ShieldCheck size={18} className="text-purple-300" /> Guide d'implémentation
                </h3>
                <div className="space-y-4 text-sm text-gray-300">
                    <div className="flex gap-4">
                        <div className="w-6 h-6 rounded-full bg-white/[0.08] flex items-center justify-center text-xs font-bold shrink-0">1</div>
                        <div>
                            <strong className="text-white block mb-1">Insertion dans le Header</strong>
                            Copiez le code et collez-le dans la section <code>&lt;head&gt;</code> de toutes vos pages (ou au moins la page d'accueil).
                        </div>
                    </div>
                    <div className="flex gap-4">
                        <div className="w-6 h-6 rounded-full bg-white/[0.08] flex items-center justify-center text-xs font-bold shrink-0">2</div>
                        <div>
                            <strong className="text-white block mb-1">Validation Google</strong>
                            Testez le code avec l'outil <a href="https://search.google.com/test/rich-results" target="_blank" className="text-purple-400 hover:underline inline-flex items-center gap-1">Résultats enrichis <ExternalLink size={10} /></a>.
                        </div>
                    </div>
                </div>
            </div>
        </div>

      </div>

      {/* HISTORIQUE DES FICHIERS */}
      {savedFiles.length > 0 && (
        <div className="mt-12 border-t border-white/[0.08] pt-10">
            <h3 className="text-xl font-sans font-bold text-white mb-6 flex items-center gap-2">
                <Archive size={20} className="text-gray-500" />
                Historique des versions
            </h3>

            <div className="grid md:grid-cols-3 lg:grid-cols-4 gap-6">
                {savedFiles.map((file) => (
                    <div key={file.id} className="ninja-card p-5 rounded-2xl border border-white/[0.08] hover:border-purple-500/30 transition-all flex flex-col">
                        <div className="flex justify-between items-start mb-3">
                            <span className="text-[10px] font-bold px-2 py-1 rounded bg-purple-500/10 text-purple-400 border border-white/[0.1] uppercase">
                                JSON-LD
                            </span>
                            <span className="text-xs text-gray-500">{new Date(file.timestamp).toLocaleDateString()}</span>
                        </div>

                        <h4 className="font-bold text-white mb-2 text-sm line-clamp-1">{file.title}</h4>

                        <div className="bg-[#000000] p-3 rounded border border-white/[0.06] mb-4 flex-1 overflow-hidden relative h-20">
                            <p className="text-[10px] text-gray-500 font-mono line-clamp-3">{file.content}</p>
                            <div className="absolute bottom-0 left-0 w-full h-6 bg-gradient-to-t from-[#000000] to-transparent"></div>
                        </div>

                        <div className="flex gap-2">
                            <button 
                                onClick={() => handleRestore(file.content)}
                                className="flex-1 py-1.5 bg-purple-500/10 hover:bg-purple-500/20 rounded text-[10px] font-bold text-purple-400 transition-colors flex items-center justify-center gap-1"
                            >
                                <Eye size={10} /> Voir
                            </button>
                            <button 
                                onClick={() => handleDownload(`schema_archive_${file.id}.jsonld`, file.content)}
                                className="flex-1 py-1.5 bg-white/[0.04] hover:bg-white/[0.08] rounded text-[10px] font-medium text-gray-300 transition-colors flex items-center justify-center gap-1"
                            >
                                <Download size={10} /> DL
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
      )}
    </div>
  );
};

export default SchemaOrg;
"}

{"content":"import React, { useState } from 'react';
import { User } from '../types';
import { generateLlmsTxt } from '../services/llms-txt-generator';
import {
  ArrowLeft, FileText, Plus, Trash2, Loader2, Copy, Check,
  Download, Sparkles, Zap, Globe, Mail, Phone, MapPin, Link,
} from 'lucide-react';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const CREDIT_COST = 3;

const LlmsTxtGenerator: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  // Form state
  const [siteName, setSiteName] = useState('');
  const [siteUrl, setSiteUrl] = useState('');
  const [description, setDescription] = useState('');
  const [entity, setEntity] = useState('Organization');
  const [contactEmail, setContactEmail] = useState('');
  const [contactPhone, setContactPhone] = useState('');
  const [contactAddress, setContactAddress] = useState('');
  const [targetAudience, setTargetAudience] = useState('');
  const [services, setServices] = useState<Array<{ name: string; description: string; url: string }>>([
    { name: '', description: '', url: '' },
  ]);
  const [keyPages, setKeyPages] = useState<Array<{ title: string; url: string; description: string }>>([
    { title: '', url: '', description: '' },
  ]);
  const [socialLinks, setSocialLinks] = useState('');

  // Result state
  const [isGenerating, setIsGenerating] = useState(false);
  const [result, setResult] = useState<{ content: string; sections: number; wordCount: number } | null>(null);
  const [copied, setCopied] = useState(false);

  const isValid = siteName && siteUrl && description && contactEmail;

  const handleGenerate = async () => {
    if (!isValid) return;
    const canProceed = onDeductCredits(CREDIT_COST);
    if (!canProceed) return;

    setIsGenerating(true);
    try {
      const output = await generateLlmsTxt({
        siteName,
        siteUrl: siteUrl.replace(/\/$/, ''),
        description,
        entity,
        services: services.filter(s => s.name),
        keyPages: keyPages.filter(p => p.title && p.url),
        contact: {
          email: contactEmail,
          ...(contactPhone ? { phone: contactPhone } : {}),
          ...(contactAddress ? { address: contactAddress } : {}),
        },
        socialLinks: socialLinks.split('\n').map(s => s.trim()).filter(Boolean),
        targetAudience: targetAudience || undefined,
      });
      setResult(output);
    } catch (err) {
      console.error('Generation failed:', err);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleCopy = () => {
    if (!result) return;
    navigator.clipboard.writeText(result.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = () => {
    if (!result) return;
    const blob = new Blob([result.content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'llms.txt';
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="w-full px-6 py-8 animate-in fade-in duration-500">
      {/* Header */}
      <div className="flex items-center gap-4 mb-8">
        <button onClick={onBack} className="p-2 rounded-xl hover:bg-white/[0.04] transition-colors">
          <ArrowLeft size={20} className="text-gray-400" />
        </button>
        <div className="flex-1">
          <div className="flex items-center gap-3">
            <h1 className="text-2xl font-bold text-white">Générateur <span className="gradient-text">llms.txt</span></h1>
            <span className="bg-emerald-500/10 text-emerald-400 text-xs font-bold px-2.5 py-1 rounded-full border border-emerald-500/20 flex items-center gap-1">
              <Sparkles size={10} /> NOUVEAU
            </span>
          </div>
          <p className="text-sm text-gray-500 mt-1">Créez votre fichier llms.txt — le "robots.txt" de l'ère IA pour vous faire référencer par les LLMs</p>
        </div>
      </div>

      {/* Info banner */}
      <div className="ninja-card p-4 mb-8 flex items-start gap-3 border-l-2 border-emerald-500/50">
        <FileText size={18} className="text-emerald-400 shrink-0 mt-0.5" />
        <div>
          <p className="text-sm text-gray-300 font-medium">Qu'est-ce que llms.txt ?</p>
          <p className="text-xs text-gray-500 mt-1">Un fichier texte placé à la racine de votre site (<code className="text-emerald-400/80">votresite.com/llms.txt</code>) qui donne aux LLMs (ChatGPT, Claude, Gemini, AI Overviews) un résumé structuré de votre identité, vos services et vos pages clés. C'est le nouveau standard pour contrôler comment les IA vous référencent.</p>
        </div>
      </div>

      <div className="grid lg:grid-cols-2 gap-6">
        {/* Left — Form */}
        <div className="space-y-6">
          {/* Identity */}
          <div className="ninja-card p-6">
            <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-4">Identité du site</h3>
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1.5">Nom du site <span className="text-red-400">*</span></label>
                  <input value={siteName} onChange={e => setSiteName(e.target.value)} placeholder="MonEntreprise"
                    className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1.5">URL <span className="text-red-400">*</span></label>
                  <input value={siteUrl} onChange={e => setSiteUrl(e.target.value)} placeholder="https://example.com"
                    className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1.5">Description <span className="text-red-400">*</span></label>
                <textarea value={description} onChange={e => setDescription(e.target.value)} rows={2} placeholder="Description concise de votre entreprise/site..."
                  className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors resize-none" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1.5">Type d'entité</label>
                  <select value={entity} onChange={e => setEntity(e.target.value)}
                    className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50">
                    <option value="Organization">Organization</option>
                    <option value="LocalBusiness">LocalBusiness</option>
                    <option value="Person">Person</option>
                    <option value="Corporation">Corporation</option>
                    <option value="SaaS">SaaS Platform</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1.5">Audience cible</label>
                  <input value={targetAudience} onChange={e => setTargetAudience(e.target.value)} placeholder="PME, marketeurs, développeurs..."
                    className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
                </div>
              </div>
            </div>
          </div>

          {/* Services */}
          <div className="ninja-card p-6">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider">Services / Produits</h3>
              <button onClick={() => setServices(prev => [...prev, { name: '', description: '', url: '' }])}
                className="flex items-center gap-1 text-xs text-purple-400 hover:text-purple-300 transition-colors">
                <Plus size={12} /> Ajouter
              </button>
            </div>
            <div className="space-y-3">
              {services.map((svc, i) => (
                <div key={i} className="bg-white/[0.02] border border-white/[0.04] rounded-xl p-3 space-y-2">
                  <div className="flex items-center gap-2">
                    <input value={svc.name} onChange={e => setServices(prev => prev.map((s, idx) => idx === i ? { ...s, name: e.target.value } : s))}
                      placeholder="Nom du service" className="flex-1 bg-transparent border-b border-white/[0.06] pb-1 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 font-medium" />
                    {services.length > 1 && (
                      <button onClick={() => setServices(prev => prev.filter((_, idx) => idx !== i))} className="text-gray-500 hover:text-red-400 p-1"><Trash2 size={12} /></button>
                    )}
                  </div>
                  <input value={svc.description} onChange={e => setServices(prev => prev.map((s, idx) => idx === i ? { ...s, description: e.target.value } : s))}
                    placeholder="Description courte..." className="w-full bg-transparent text-sm text-gray-400 focus:outline-none" />
                </div>
              ))}
            </div>
          </div>

          {/* Key Pages */}
          <div className="ninja-card p-6">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider">Pages Clés</h3>
              <button onClick={() => setKeyPages(prev => [...prev, { title: '', url: '', description: '' }])}
                className="flex items-center gap-1 text-xs text-purple-400 hover:text-purple-300 transition-colors">
                <Plus size={12} /> Ajouter
              </button>
            </div>
            <div className="space-y-3">
              {keyPages.map((page, i) => (
                <div key={i} className="bg-white/[0.02] border border-white/[0.04] rounded-xl p-3 space-y-2">
                  <div className="flex items-center gap-2">
                    <input value={page.title} onChange={e => setKeyPages(prev => prev.map((p, idx) => idx === i ? { ...p, title: e.target.value } : p))}
                      placeholder="Titre de la page" className="flex-1 bg-transparent border-b border-white/[0.06] pb-1 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 font-medium" />
                    {keyPages.length > 1 && (
                      <button onClick={() => setKeyPages(prev => prev.filter((_, idx) => idx !== i))} className="text-gray-500 hover:text-red-400 p-1"><Trash2 size={12} /></button>
                    )}
                  </div>
                  <input value={page.url} onChange={e => setKeyPages(prev => prev.map((p, idx) => idx === i ? { ...p, url: e.target.value } : p))}
                    placeholder="/pricing, /about, /docs..." className="w-full bg-transparent text-xs text-gray-500 focus:outline-none" />
                  <input value={page.description} onChange={e => setKeyPages(prev => prev.map((p, idx) => idx === i ? { ...p, description: e.target.value } : p))}
                    placeholder="Description de la page..." className="w-full bg-transparent text-sm text-gray-400 focus:outline-none" />
                </div>
              ))}
            </div>
          </div>

          {/* Contact & Social */}
          <div className="ninja-card p-6">
            <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-4">Contact & Réseaux</h3>
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1.5 flex items-center gap-1.5"><Mail size={12} /> Email <span className="text-red-400">*</span></label>
                  <input value={contactEmail} onChange={e => setContactEmail(e.target.value)} placeholder="contact@example.com" type="email"
                    className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-1.5 flex items-center gap-1.5"><Phone size={12} /> Téléphone</label>
                  <input value={contactPhone} onChange={e => setContactPhone(e.target.value)} placeholder="+33 1 23 45 67 89"
                    className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1.5 flex items-center gap-1.5"><MapPin size={12} /> Adresse</label>
                <input value={contactAddress} onChange={e => setContactAddress(e.target.value)} placeholder="123 Rue Example, 75001 Paris"
                  className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1.5 flex items-center gap-1.5"><Link size={12} /> Réseaux sociaux (un par ligne)</label>
                <textarea value={socialLinks} onChange={e => setSocialLinks(e.target.value)} rows={3}
                  placeholder={"https://twitter.com/monentreprise\nhttps://linkedin.com/company/monentreprise\nhttps://github.com/monentreprise"}
                  className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors resize-none" />
              </div>
            </div>
          </div>

          {/* Generate Button */}
          <button onClick={handleGenerate} disabled={isGenerating || !isValid}
            className={`w-full py-3.5 rounded-2xl font-semibold text-sm flex items-center justify-center gap-2 transition-all duration-300 ${
              isGenerating || !isValid ? 'bg-gray-700/50 text-gray-500 cursor-not-allowed' : 'btn-gradient text-white hover:shadow-xl hover:shadow-purple-900/30 hover:-translate-y-0.5'
            }`}>
            {isGenerating ? (<><Loader2 size={16} className="animate-spin" /> Génération en cours...</>) : (<><Zap size={16} /> Générer llms.txt ({CREDIT_COST} Gas)</>)}
          </button>
        </div>

        {/* Right — Result */}
        <div className="space-y-6">
          {!result && !isGenerating && (
            <div className="ninja-card p-12 flex flex-col items-center justify-center text-center sticky top-20">
              <div className="p-4 bg-emerald-500/10 rounded-2xl mb-4">
                <FileText size={40} className="text-emerald-400" />
              </div>
              <h3 className="text-lg font-bold text-gray-300 mb-2">llms.txt</h3>
              <p className="text-sm text-gray-500 max-w-sm">Remplissez les informations à gauche pour générer votre fichier llms.txt optimisé pour les moteurs de réponse IA</p>
              <div className="mt-6 text-left w-full max-w-sm">
                <p className="text-xs text-gray-600 mb-2">Le fichier contiendra :</p>
                <div className="space-y-1.5">
                  {['Identité & description', 'Liste des services', 'Pages clés avec liens', 'Informations de contact', 'Instructions pour les IA'].map(item => (
                    <div key={item} className="flex items-center gap-2 text-xs text-gray-500">
                      <div className="w-1 h-1 rounded-full bg-emerald-500" />
                      {item}
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {isGenerating && (
            <div className="ninja-card p-12 flex flex-col items-center justify-center text-center">
              <Loader2 size={40} className="text-emerald-400 animate-spin mb-4" />
              <h3 className="text-lg font-bold text-gray-300 mb-2">Génération en cours...</h3>
              <p className="text-sm text-gray-500">Structuration de vos informations pour les LLMs</p>
            </div>
          )}

          {result && !isGenerating && (
            <div className="space-y-4">
              {/* Stats */}
              <div className="grid grid-cols-2 gap-3">
                <div className="ninja-card p-4 text-center">
                  <p className="text-2xl font-bold text-emerald-400">{result.sections}</p>
                  <p className="text-xs text-gray-500 mt-1">Sections</p>
                </div>
                <div className="ninja-card p-4 text-center">
                  <p className="text-2xl font-bold text-purple-400">{result.wordCount}</p>
                  <p className="text-xs text-gray-500 mt-1">Mots</p>
                </div>
              </div>

              {/* Code preview */}
              <div className="ninja-card overflow-hidden">
                <div className="flex items-center justify-between px-4 py-3 border-b border-white/[0.06]">
                  <div className="flex items-center gap-2">
                    <FileText size={14} className="text-emerald-400" />
                    <span className="text-sm font-semibold text-gray-300">llms.txt</span>
                    <span className="text-xs text-gray-500 bg-white/[0.04] px-2 py-0.5 rounded">TXT</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <button onClick={handleCopy} className="flex items-center gap-1.5 text-xs text-gray-400 hover:text-purple-400 transition-colors px-2 py-1 rounded hover:bg-white/[0.04]">
                      {copied ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
                      {copied ? 'Copié !' : 'Copier'}
                    </button>
                    <button onClick={handleDownload} className="flex items-center gap-1.5 text-xs text-gray-400 hover:text-purple-400 transition-colors px-2 py-1 rounded hover:bg-white/[0.04]">
                      <Download size={12} /> Télécharger
                    </button>
                  </div>
                </div>
                <pre className="p-4 text-xs text-gray-300 overflow-x-auto max-h-[600px] overflow-y-auto leading-relaxed whitespace-pre-wrap">
                  <code>{result.content}</code>
                </pre>
              </div>

              {/* Instructions */}
              <div className="ninja-card p-4">
                <h4 className="text-sm font-semibold text-gray-300 mb-2 flex items-center gap-2">
                  <Globe size={14} className="text-purple-400" /> Comment déployer
                </h4>
                <ol className="space-y-1.5 text-xs text-gray-500">
                  <li>1. Téléchargez le fichier <code className="text-emerald-400">llms.txt</code></li>
                  <li>2. Placez-le à la racine de votre site : <code className="text-emerald-400">{siteUrl}/llms.txt</code></li>
                  <li>3. Ajoutez dans votre <code className="text-emerald-400">robots.txt</code> : <code className="text-purple-300">Sitemap: {siteUrl}/llms.txt</code></li>
                  <li>4. Ajoutez un <code className="text-emerald-400">&lt;link&gt;</code> dans votre <code>&lt;head&gt;</code> : <code className="text-purple-300">&lt;link rel="llms" href="/llms.txt"&gt;</code></li>
                </ol>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default LlmsTxtGenerator;
"}

{"content":"import React, { useState } from 'react';
import { generateBlogArchitecture, generateFullArticle } from '../services/generator';
import { ArrowLeft, PenTool, Link as LinkIcon, Download, Copy, Check, Sparkles, Loader2, FileText, AlignLeft, Bot, ExternalLink, Award } from 'lucide-react';
import { User } from '../types';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
  onNavigateToPublisher?: (data: { topic: string, url: string, brief: string }) => void;
}

const BlogOptimizer: React.FC<Props> = ({ onBack, user, onDeductCredits, onNavigateToPublisher }) => {
  const [topic, setTopic] = useState('');
  const [url, setUrl] = useState('');
  const [result, setResult] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isWritingArticle, setIsWritingArticle] = useState(false);
  const [copied, setCopied] = useState(false);
  const [mode, setMode] = useState<'brief' | 'article'>('brief');

  const BRIEF_COST = 20;
  const FULL_ARTICLE_COST = 50;

  const handleGenerateBrief = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topic && !url) {
      alert("Veuillez saisir au moins un sujet ou une URL.");
      return;
    }

    if (onDeductCredits(BRIEF_COST)) {
      setIsGenerating(true);
      setMode('brief');
      try {
        const output = await generateBlogArchitecture(topic, url);
        setResult(output);
      } catch (error) {
        console.error(error);
        alert("Erreur lors de la génération.");
      } finally {
        setIsGenerating(false);
      }
    }
  };

  const handleWriteForMe = async () => {
    if (!result) return;

    if (onNavigateToPublisher) {
        onNavigateToPublisher({
            topic: topic || "Sujet non spécifié",
            url: url || "",
            brief: result
        });
    }
  };

  const handleCopy = () => {
    if (result) {
      navigator.clipboard.writeText(result);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const handleDownload = () => {
    if (result) {
      const blob = new Blob([result], { type: 'text/markdown' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${mode === 'article' ? 'Article_AEO' : 'Brief'}_${topic.replace(/\s+/g, '_') || 'Optimized'}.md`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    }
  };

  return (
    <div className="w-full px-4 py-10 animate-in fade-in duration-500 min-h-screen">
      <button onClick={onBack} className="flex items-center text-gray-500 hover:text-white mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" /> Retour
      </button>

      <div className="grid lg:grid-cols-12 gap-8 h-full">
        {/* Left Panel: Inputs */}
        <div className="lg:col-span-4 space-y-6">
          <div>
            <h1 className="text-3xl font-sans font-bold text-white mb-2 flex items-center gap-3">
              <div className="w-10 h-10 rounded-2xl bg-pink-500/20 flex items-center justify-center text-pink-400 border border-pink-500/30">
                <PenTool size={20} />
              </div>
              Blog Optimiser
            </h1>
            <p className="text-gray-500">Générez des briefs de rédaction structurés pour maximiser vos chances de Citation IA (GEO).</p>
          </div>

          <div className="ninja-card p-6 rounded-2xl border border-white/[0.08]">
            <form onSubmit={handleGenerateBrief} className="space-y-6">

              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-300 flex items-center gap-2">
                  <AlignLeft size={16} className="text-pink-400" /> Sujet / Mot-clé cible
                </label>
                <input 
                  type="text" 
                  value={topic}
                  onChange={(e) => setTopic(e.target.value)}
                  placeholder="Ex: Optimisation AEO pour e-commerce"
                  className="w-full bg-black/40 border border-white/[0.08] rounded-xl p-3 text-white placeholder-gray-600 focus:border-pink-500/50 outline-none transition-colors"
                />
              </div>

              <div className="relative flex items-center gap-4">
                <div className="h-px bg-white/[0.08] flex-1"></div>
                <span className="text-xs text-gray-500 uppercase font-bold">ET / OU</span>
                <div className="h-px bg-white/[0.08] flex-1"></div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-300 flex items-center gap-2">
                  <LinkIcon size={16} className="text-pink-400" /> URL à analyser (Optionnel)
                </label>
                <input 
                  type="url" 
                  value={url}
                  onChange={(e) => setUrl(e.target.value)}
                  placeholder="https://votre-site.com/blog/article-existant"
                  className="w-full bg-black/40 border border-white/[0.08] rounded-xl p-3 text-white placeholder-gray-600 focus:border-pink-500/50 outline-none transition-colors"
                />
              </div>

              <div className="pt-4 border-t border-white/[0.06]">
                <div className="flex justify-between items-center mb-4 text-xs text-gray-500">
                  <span>Coût Brief</span>
                  <span className="font-bold text-white">{BRIEF_COST} Crédits</span>
                </div>
                <button 
                  type="submit" 
                  disabled={isGenerating || isWritingArticle}
                  className="w-full py-3 bg-pink-600 hover:bg-pink-700 text-white font-bold rounded-2xl transition-all shadow-lg shadow-pink-500/20 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                >
                  {isGenerating ? <Loader2 className="animate-spin" size={20} /> : <FileText size={20} />}
                  {isGenerating ? 'Analyse en cours...' : 'Générer le Brief'}
                </button>
              </div>
            </form>
          </div>

          {/* Educational Points */}
          <div className="ninja-card p-5 rounded-2xl border border-white/[0.08]">
            <h3 className="font-bold text-white mb-3 text-sm">Pourquoi ce format ?</h3>
            <ul className="space-y-3 text-xs text-gray-500">
              <li className="flex gap-2">
                <Check size={14} className="text-pink-400 shrink-0 mt-0.5" />
                Structure les Hn pour l'extraction rapide.
              </li>
              <li className="flex gap-2">
                <Check size={14} className="text-pink-400 shrink-0 mt-0.5" />
                Intègre une FAQ obligatoire pour le Voice Search.
              </li>
              <li className="flex gap-2">
                <Check size={14} className="text-pink-400 shrink-0 mt-0.5" />
                Prépare les données structurées JSON-LD.
              </li>
            </ul>
          </div>
        </div>

        {/* Right Panel: Results & Actions */}
        <div className="lg:col-span-8 flex flex-col h-full gap-6">

          {/* Main Content Area (Result) */}
          <div className="flex-1 flex flex-col h-[calc(100vh-250px)]">
            {result ? (
              <div className="flex flex-col h-full bg-[#0f1115] border border-white/[0.08] rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in duration-300">
                {/* Result Header */}
                <div className="p-4 border-b border-white/[0.08] flex items-center justify-between bg-white/[0.04] shrink-0">
                  <div className="flex items-center gap-2 text-sm font-medium text-white">
                    {mode === 'article' ? <Bot size={16} className="text-purple-300" /> : <FileText size={16} className="text-pink-400" />} 
                    {mode === 'article' ? 'Article Rédigé par IA' : 'Brief Généré'}
                  </div>
                  <div className="flex gap-2">
                    <button onClick={handleCopy} className="flex items-center gap-2 px-3 py-1.5 bg-white/[0.04] hover:bg-purple-500/10 rounded-full text-xs font-medium text-white border border-white/[0.08] transition-colors">
                      {copied ? <Check size={14} className="text-purple-300" /> : <Copy size={14} />}
                      {copied ? 'Copié' : 'Copier'}
                    </button>
                    <button onClick={handleDownload} className="flex items-center gap-2 px-3 py-1.5 bg-gradient-to-r from-purple-500 to-violet-600 text-white hover:from-purple-600 hover:to-violet-700 rounded-full text-xs font-bold transition-colors">
                      <Download size={14} /> Télécharger MD
                    </button>
                  </div>
                </div>

                {/* Markdown Content */}
                <div className="flex-1 overflow-auto p-8 bg-[#000000] custom-scrollbar">
                  {isWritingArticle ? (
                    <div className="h-full flex flex-col items-center justify-center space-y-4">
                        <Loader2 className="animate-spin text-pink-500" size={48} />
                        <p className="text-gray-500 animate-pulse">Rédaction de l'article optimisé en cours...</p>
                    </div>
                  ) : (
                    <pre className="whitespace-pre-wrap font-mono text-sm text-gray-300 leading-relaxed selection:bg-pink-500/30">
                      {result}
                    </pre>
                  )}
                </div>
              </div>
            ) : (
              <div className="h-full flex flex-col items-center justify-center ninja-card rounded-2xl border border-white/[0.06] text-gray-500 border-dashed">
                <div className="w-16 h-16 bg-white/[0.04] rounded-full flex items-center justify-center mb-6">
                  <FileText size={32} className="opacity-20" />
                </div>
                <p className="text-lg font-medium text-gray-500 mb-2">Prêt à rédiger ?</p>
                <p className="text-sm max-w-sm text-center">
                  Entrez un sujet ou une URL pour générer une architecture d'article optimisée pour les Answer Engines.
                </p>
              </div>
            )}
          </div>

          {/* Action Bar / Upsell (Only visible if result exists) */}
          {result && !isWritingArticle && (
             <div className="grid md:grid-cols-1 gap-4 animate-in slide-in-from-bottom-4 duration-500">

                {/* Option 2: Write For Me (New Flow) */}
                <div className="bg-gradient-to-r from-pink-900/20 to-purple-900/20 p-5 rounded-2xl border border-white/[0.08] flex items-center justify-between group hover:border-white/20 transition-all">
                    <div className="flex items-center gap-4">
                        <div className="p-3 bg-white/[0.04] rounded-full text-white group-hover:bg-purple-500/10 transition-colors">
                            <PenTool size={24} />
                        </div>
                        <div>
                            <h4 className="font-bold text-white mb-1 flex items-center gap-2">
                                Write For Me & Publisher
                            </h4>
                            <p className="text-xs text-gray-500">
                                Commandez la rédaction complète et la publication sur un site d'autorité.
                            </p>
                        </div>
                    </div>

                    <button 
                        onClick={handleWriteForMe}
                        className="px-6 py-2.5 bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold rounded-full hover:from-purple-600 hover:to-violet-700 transition-colors flex items-center gap-2 shadow-lg"
                    >
                        <Sparkles size={16} className="text-pink-600" />
                        Commander la Rédaction
                    </button>
                </div>

             </div>
          )}

        </div>
      </div>
    </div>
  );
};

export default BlogOptimizer;
"}

{"content":"import { GoogleGenAI } from "@google/genai";
import { BLOG_WRITER_SYSTEM_PROMPT, FULL_ARTICLE_SYSTEM_PROMPT } from './blog_prompt_db';

const getApiKey = () => {
