  const [platformName, setPlatformName] = useState('');
  const [copied, setCopied] = useState(false);
  const [isUnlocked, setIsUnlocked] = useState(false);

  const GENERATION_COST = 10;

  // Initialize with data from history
  useEffect(() => {
    const processUrl = (analysis: AnalysisResult | undefined) => {
        if (!analysis) {
            // Mode Demo / Fallback
            const demoUrl = "https://monsite-wordpress.com";
            setCurrentContent(parseCurrentRobotsTxt(demoUrl));
            setOptimizedContent(generateOptimizedRobotsTxt(demoUrl));
            setPlatformName(getDetectedPlatformName(demoUrl));
            setIsUnlocked(false);
            return;
        }

        const url = analysis.url;
        setCurrentContent(parseCurrentRobotsTxt(url));
        setPlatformName(getDetectedPlatformName(url));

        // Check if previously unlocked/saved in history
        if (analysis.robotsTxtData && analysis.robotsTxtData.isUnlocked) {
            setOptimizedContent(analysis.robotsTxtData.content);
            setIsUnlocked(true);
        } else {
            // Fresh generation (locked)
            setOptimizedContent(generateOptimizedRobotsTxt(url));
            setIsUnlocked(false);
        }
    };

    if (history.length > 0) {
      processUrl(history[selectedAnalysisIndex]);
    } else {
      processUrl(undefined);
    }
  }, [selectedAnalysisIndex, history]);

  const handleUnlock = () => {
    // La vérification de connexion et de solde est gérée par onDeductCredits
    if (onDeductCredits(GENERATION_COST)) {
        setIsUnlocked(true);

        // Persist to analysis history
        if (history.length > 0) {
            onUpdateAnalysis(selectedAnalysisIndex, {
                robotsTxtData: {
                    content: optimizedContent,
                    isUnlocked: true,
                    platform: platformName,
                    generatedAt: new Date().toISOString()
                }
            });
        }

        // Save to file history
        onSaveFile({
            id: `robots_${Date.now()}`,
            type: 'fiche', // Generic
            title: `Robots.txt - ${history[selectedAnalysisIndex]?.url || 'Demo'}`,
            content: optimizedContent,
            timestamp: new Date().toISOString()
        });
    }
  };

  const handleDownload = (filename?: string, content?: string) => {
    const blob = new Blob([content || optimizedContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename || 'robots.txt';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleCopy = (content?: string) => {
    navigator.clipboard.writeText(content || optimizedContent);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const getImplementationSteps = (platform: string) => {
    if (platform.includes('WordPress')) {
      return {
        title: "Installation sur WordPress",
        icon: <Settings size={20} />,
        steps: [
          "Connectez-vous à votre tableau de bord WordPress (/wp-admin).",
          "Si vous utilisez Yoast SEO : Allez dans 'SEO' → 'Outils' → 'Éditeur de fichiers'.",
          "Si vous utilisez RankMath : Allez dans 'Rank Math' → 'Réglages généraux' → 'Modifier robots.txt'.",
          "Si aucun plugin SEO : Utilisez un plugin 'File Manager' ou un accès FTP.",
          "Copiez le code généré ci-dessus et remplacez tout le contenu existant.",
          "Sauvegardez les modifications."
        ]
      };
    }
    if (platform.includes('Shopify')) {
      return {
        title: "Installation sur Shopify",
        icon: <FileJson size={20} />,
        steps: [
          "Depuis votre admin Shopify, allez dans 'Boutique en ligne' → 'Thèmes'.",
          "Cliquez sur le bouton 'Actions' (ou les trois points) → 'Modifier le code'.",
          "Dans la barre de recherche de fichiers, tapez 'robots'.",
          "Cliquez sur 'Ajouter un nouveau modèle' → sélectionnez 'robots.txt' si robots.txt.liquid n'existe pas.",
          "Collez le code optimisé dans le fichier.",
          "Cliquez sur 'Enregistrer' en haut à droite."
        ]
      };
    }
    if (platform.includes('SaaS') || platform.includes('App')) {
      return {
        title: "Installation App Web (React/Next.js/Vue)",
        icon: <Terminal size={20} />,
        steps: [
          "Localisez le dossier 'public' ou 'static' à la racine de votre projet.",
          "Créez ou modifiez le fichier nommé 'robots.txt'.",
          "Collez le contenu généré.",
          "Pour Next.js (App Router) : Vous pouvez alternativement créer un fichier `app/robots.ts` et retourner cet objet.",
          "Redéployez votre application pour appliquer les changements."
        ]
      };
    }
    // Default
    return {
      title: "Installation Standard (Apache/Nginx/FTP)",
      icon: <Server size={20} />,
      steps: [
        "Connectez-vous à votre serveur via FTP (FileZilla) ou Gestionnaire de fichiers (cPanel).",
        "Naviguez vers le dossier racine publique (souvent /public_html/ ou /www/).",
        "Cherchez le fichier 'robots.txt'. S'il n'existe pas, créez-le.",
        "Ouvrez le fichier avec un éditeur de texte.",
        "Collez le code généré ci-dessus et sauvegardez.",
        "Vérifiez l'accès en allant sur votre-site.com/robots.txt"
      ]
    };
  };

  const guide = getImplementationSteps(platformName);

  const handleRestore = (content: string) => {
      setOptimizedContent(content);
      setIsUnlocked(true);
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="w-full px-4 py-10 animate-in fade-in duration-500 min-h-screen">
      <button onClick={onBack} className="flex items-center text-gray-500 hover:text-white mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" /> Retour
      </button>

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
        <div>
          <h1 className="text-3xl font-sans font-bold text-white mb-2 flex items-center gap-3">
             <div className="w-10 h-10 rounded-2xl bg-blue-500/20 flex items-center justify-center text-blue-400 border border-blue-500/30">
              <FileCode size={24} />
            </div>
            Robots.txt Optimizer
          </h1>
          <p className="text-gray-500">Ouvrez les portes aux bots IA (GPTBot, Claude, Gemini) tout en sécurisant votre site.</p>
        </div>

        {/* Project Selector */}
        {history.length > 0 && (
            <div className="relative group w-full md:w-auto">
            <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none text-gray-500">
                <History size={16} />
            </div>
            <select 
                value={selectedAnalysisIndex}
                onChange={(e) => setSelectedAnalysisIndex(Number(e.target.value))}
                className="appearance-none bg-white/[0.04] border border-white/[0.08] text-white pl-10 pr-10 py-2.5 rounded-2xl focus:outline-none focus:border-blue-500/50 w-full min-w-[250px] cursor-pointer hover:bg-white/[0.08] transition-colors"
            >
                {history.map((analysis, idx) => (
                <option key={idx} value={idx} className="bg-[#1a1d24]">
                    {new URL(analysis.url).hostname}
                </option>
                ))}
            </select>
            <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" size={16} />
            </div>
        )}
      </div>

      <div className="grid lg:grid-cols-2 gap-8 mb-12">

        {/* Left Column: Context & Education (Always Visible) */}
        <div className="space-y-6">
            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] relative overflow-hidden">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                    <Server size={64} />
                </div>
                <h3 className="text-lg font-bold text-white mb-2 flex items-center gap-2">
                    <Eye size={18} className="text-blue-400" /> Analyse Technique
                </h3>
                <div className="flex items-center gap-2 mb-4">
                    <span className="text-sm text-gray-500">Architecture détectée :</span>
                    <span className="px-2 py-1 bg-blue-500/20 text-blue-300 text-xs font-bold rounded uppercase border border-blue-500/30">
                        {platformName}
                    </span>
                </div>
                <p className="text-sm text-gray-500 leading-relaxed mb-4">
                    Nous avons adapté les règles <code>Disallow</code> pour masquer les routes sensibles spécifiques à votre technologie ({platformName}), tout en ouvrant les routes de contenu public aux bots IA.
                </p>

                <div className="bg-[#111111] p-4 rounded-2xl border border-white/[0.06] font-mono text-xs text-gray-500 overflow-auto max-h-[150px] relative">
                    <div className="absolute top-2 right-2 text-[10px] text-gray-600 font-sans bg-white/[0.04] px-2 py-1 rounded">Fichier Actuel (Simulé)</div>
                    <pre>{currentContent}</pre>
                </div>
            </div>

            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08]">
                <h3 className="text-lg font-bold text-white mb-4">La Stratégie "Open-AI, Closed-Admin"</h3>
                <ul className="space-y-4">
                    <li className="flex items-start gap-3">
                        <div className="w-8 h-8 rounded-full bg-green-500/20 flex items-center justify-center shrink-0 text-green-400"><Bot size={16} /></div>
                        <div>
                            <p className="text-sm font-bold text-gray-200">Whitelist Explicite</p>
                            <p className="text-xs text-gray-500">
                                GPTBot, CCBot et Google-Extended sont souvent bloqués par défaut par les pare-feux. Ce fichier force leur autorisation pour garantir votre citation.
                            </p>
                        </div>
                    </li>
                    <li className="flex items-start gap-3">
                        <div className="w-8 h-8 rounded-full bg-purple-500/20 flex items-center justify-center shrink-0 text-purple-400"><AlertTriangle size={16} /></div>
                        <div>
                            <p className="text-sm font-bold text-gray-200">Protection Budgétaire</p>
                            <p className="text-xs text-gray-500">
                                En bloquant les dossiers <code>/api/</code> ou <code>/search/</code>, nous évitons que les bots IA ne consomment vos ressources serveur inutilement.
                            </p>
                        </div>
                    </li>
                </ul>
            </div>
        </div>

        {/* Right Column: Optimized Output (Locked or Unlocked based on history) */}
        <div className="flex flex-col">
            <div className="bg-[#0f1115] border border-white/[0.08] rounded-2xl flex flex-col shadow-2xl overflow-hidden relative">

                <div className="p-4 border-b border-white/[0.08] flex items-center justify-between bg-white/[0.04]">
                    <div className="flex items-center gap-2">
                        <div className={`w-2 h-2 rounded-full ${isUnlocked ? 'bg-purple-400 animate-pulse' : 'bg-gray-500'}`}></div>
                        <span className="text-sm font-bold text-white">robots.txt (Optimisé AEO)</span>
                        {!isUnlocked && <Lock size={14} className="text-gray-500 ml-1" />}
                        {isUnlocked && history.length > 0 && history[selectedAnalysisIndex]?.robotsTxtData && (
                            <span className="text-xs text-purple-300 bg-purple-400/10 px-2 py-0.5 rounded ml-2">Payé</span>
                        )}
                    </div>
                    <div className="flex gap-2">
                        {isUnlocked ? (
                            <>
                                <button onClick={() => handleCopy()} className="flex items-center gap-2 px-3 py-1.5 bg-white/[0.04] hover:bg-white/[0.08] rounded-full text-xs font-medium text-white border border-white/[0.08] transition-colors">
                                    {copied ? <Check size={14} className="text-purple-300" /> : <Copy size={14} />}
                                    {copied ? 'Copié' : 'Copier'}
                                </button>
                                <button onClick={() => handleDownload()} className="flex items-center gap-2 px-3 py-1.5 bg-gradient-to-r from-purple-500 to-violet-600 text-white hover:from-purple-600 hover:to-violet-700 rounded-full text-xs font-bold transition-colors">
                                    <Download size={14} /> Télécharger
                                </button>
                            </>
                        ) : (
                            <span className="text-xs text-gray-500 flex items-center gap-1 bg-white/[0.04] px-2 py-1 rounded">
                                <Lock size={10} /> Aperçu verrouillé
                            </span>
                        )}
                    </div>
                </div>

                <div className="relative bg-[#000000] p-6 h-[300px] group">
                    {isUnlocked ? (
                        <pre className="font-mono text-sm text-purple-100/90 whitespace-pre-wrap leading-relaxed selection:bg-purple-400/30 overflow-auto h-full">
                            {optimizedContent}
                        </pre>
                    ) : (
                        <>
                            {/* Blurry Code Placeholder */}
                            <pre className="font-mono text-sm text-gray-600 blur-[4px] opacity-50 select-none overflow-hidden h-full">
                                {`User-agent: GPTBot\nAllow: /\nUser-agent: CCBot\nAllow: /\n\n# Secure Admin Paths\nDisallow: /wp-admin/\nDisallow: /private/\n\n# Sitemap Declaration\nSitemap: https://...`}
                            </pre>

                            {/* Unlock Overlay */}
                            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 backdrop-blur-[2px] z-10 p-6 text-center">
                                <div className="w-12 h-12 rounded-full bg-purple-500/20 flex items-center justify-center text-purple-400 mb-4 border border-primary/30">
                                    <Lock size={24} />
                                </div>
                                <h4 className="text-white font-bold text-lg mb-2">Fichier Optimisé Prêt</h4>
                                <p className="text-gray-300 text-sm mb-6 max-w-xs">
                                    Débloquez votre fichier <code>robots.txt</code> configuré pour GPT-4, Claude et Gemini.
                                </p>
                                <button 
                                    onClick={handleUnlock}
                                    className="px-6 py-3 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white font-bold rounded-2xl transition-all transform hover:scale-105 shadow-[0_0_20px_rgba(168,85,247,0.2)] flex items-center gap-2"
                                >
                                    <Zap size={16} />
                                    Générer (-{GENERATION_COST} crédits)
                                </button>
                                <p className="text-xs text-gray-500 mt-4">
                                    Solde actuel : <span className="text-white font-bold">{user ? user.credits : 0}</span> crédits
                                </p>
                            </div>
                        </>
                    )}
                </div>

                <div className="p-4 border-t border-white/[0.08] bg-white/[0.04] text-xs text-gray-500 flex justify-between items-center">
                    <span>Généré pour : {platformName}</span>
                    <span>{isUnlocked ? `Taille : ~${optimizedContent.length} bytes` : 'En attente de déverrouillage'}</span>
                </div>
            </div>
        </div>
      </div>

      {/* IMPLEMENTATION GUIDE SECTION (Blurred if locked to add value) */}
      <div className={`border-t border-white/[0.08] pt-10 transition-all duration-500 ${!isUnlocked ? 'opacity-50 blur-[2px] pointer-events-none grayscale' : ''}`}>
        <h2 className="text-2xl font-sans font-bold text-white mb-6 flex items-center gap-3">
            <div className="w-8 h-8 rounded-full bg-white/[0.04] flex items-center justify-center text-gray-300">
                {guide.icon}
            </div>
            Guide d'implémentation : {guide.title}
        </h2>

        <div className="grid md:grid-cols-2 gap-8 items-start">
            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08] bg-gradient-to-br from-white/5 to-transparent">
                <ol className="relative border-l border-white/[0.08] ml-3 space-y-8">
                    {guide.steps.map((step, index) => (
                        <li key={index} className="pl-8 relative group">
                            <span className="absolute -left-[17px] top-0 flex items-center justify-center w-8 h-8 bg-[#000000] border border-white/20 rounded-full text-xs font-bold text-gray-500 group-hover:text-purple-400 group-hover:border-primary transition-colors">
                                {index + 1}
                            </span>
                            <p className="text-gray-300 leading-relaxed group-hover:text-white transition-colors text-sm">
                                {step}
                            </p>
                        </li>
                    ))}
                </ol>
            </div>

            <div className="space-y-6">
                <div className="bg-purple-500/10 border border-white/[0.1] rounded-2xl p-6">
                    <h4 className="text-purple-300 font-bold mb-2 flex items-center gap-2">
                        <AlertTriangle size={18} /> Point de Vigilance
                    </h4>
                    <p className="text-sm text-purple-200/80 leading-relaxed">
                        Une erreur dans le fichier <code>robots.txt</code> peut désindexer totalement votre site de Google. 
                        Avant de mettre en production, testez toujours votre fichier avec l'outil de test du fichier robots.txt de la Google Search Console.
                    </p>
                </div>

                <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] flex items-center gap-4">
                    <div className="w-12 h-12 rounded-full bg-purple-500/10 flex items-center justify-center text-purple-400 shrink-0">
                        <Globe size={24} />
                    </div>
                    <div>
                        <h4 className="font-bold text-white text-sm">Vérification Post-Install</h4>
                        <p className="text-xs text-gray-500 mt-1">
                            Accédez à <code>{history.length > 0 ? new URL(history[selectedAnalysisIndex].url).origin : 'votre-site.com'}/robots.txt</code> pour confirmer que le nouveau contenu est bien en ligne.
                        </p>
                    </div>
                </div>
            </div>
        </div>
      </div>

      {/* HISTORIQUE DES FICHIERS */}
      {savedFiles.length > 0 && (
        <div className="mt-12 border-t border-white/[0.08] pt-10">
            <h3 className="text-xl font-sans font-bold text-white mb-6 flex items-center gap-2">
                <Archive size={20} className="text-gray-500" />
                Historique des versions
            </h3>

            <div className="grid md:grid-cols-3 lg:grid-cols-4 gap-6">
                {savedFiles.map((file) => (
                    <div key={file.id} className="ninja-card p-5 rounded-2xl border border-white/[0.08] hover:border-blue-500/30 transition-all flex flex-col">
                        <div className="flex justify-between items-start mb-3">
                            <span className="text-[10px] font-bold px-2 py-1 rounded bg-blue-500/10 text-blue-400 border border-blue-500/20 uppercase">
                                robots.txt
                            </span>
                            <span className="text-xs text-gray-500">{new Date(file.timestamp).toLocaleDateString()}</span>
                        </div>

                        <h4 className="font-bold text-white mb-2 text-sm line-clamp-1">{file.title}</h4>

                        <div className="bg-[#000000] p-3 rounded border border-white/[0.06] mb-4 flex-1 overflow-hidden relative h-20">
                            <p className="text-[10px] text-gray-500 font-mono line-clamp-3">{file.content}</p>
                            <div className="absolute bottom-0 left-0 w-full h-6 bg-gradient-to-t from-[#000000] to-transparent"></div>
                        </div>

                        <div className="flex gap-2">
                            <button 
                                onClick={() => handleRestore(file.content)}
                                className="flex-1 py-1.5 bg-purple-500/10 hover:bg-purple-500/20 rounded text-[10px] font-bold text-purple-400 transition-colors flex items-center justify-center gap-1"
                            >
                                <Eye size={10} /> Voir
                            </button>
                            <button 
                                onClick={() => handleDownload(`robots_archive_${file.id}.txt`, file.content)}
                                className="flex-1 py-1.5 bg-white/[0.04] hover:bg-white/[0.08] rounded text-[10px] font-medium text-gray-300 transition-colors flex items-center justify-center gap-1"
                            >
                                <Download size={10} /> DL
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
      )}

    </div>
  );
};

export default RobotsTxt;
"}

{"content":"import React, { useState } from 'react';
import { User, ContentWriterInput, GeneratedContent, ContentVertical, ContentType } from '../types';
import { generateContent } from '../services/content_writer';
import { useTranslation } from '../i18n';
import { ArrowLeft, Feather, Copy, Download, Check, Loader2, RefreshCw, ShoppingBag, Cloud, Building, UtensilsCrossed, Heart, DollarSign, Scale, GraduationCap, Globe, FileText, Layout, Mail, Tag, Share2, Newspaper, BookOpen, Send, Sparkles } from 'lucide-react';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const VERTICAL_ICONS: { id: ContentVertical; icon: React.ElementType; color: string }[] = [
  { id: 'ecommerce', icon: ShoppingBag, color: 'text-pink-400' },
  { id: 'saas', icon: Cloud, color: 'text-blue-400' },
  { id: 'immobilier', icon: Building, color: 'text-purple-400' },
  { id: 'restauration', icon: UtensilsCrossed, color: 'text-orange-400' },
  { id: 'sante', icon: Heart, color: 'text-red-400' },
  { id: 'finance', icon: DollarSign, color: 'text-purple-300' },
  { id: 'juridique', icon: Scale, color: 'text-purple-400' },
  { id: 'education', icon: GraduationCap, color: 'text-cyan-400' },
  { id: 'general', icon: Globe, color: 'text-gray-500' },
];

const CONTENT_TYPE_ICONS: { id: ContentType; icon: React.ElementType; cost: number }[] = [
  { id: 'product_description', icon: FileText, cost: 2 },
  { id: 'landing_page', icon: Layout, cost: 3 },
  { id: 'sales_email', icon: Mail, cost: 2 },
  { id: 'meta_tags', icon: Tag, cost: 1 },
  { id: 'social_post', icon: Share2, cost: 1 },
  { id: 'press_release', icon: Newspaper, cost: 2 },
  { id: 'case_study', icon: BookOpen, cost: 3 },
  { id: 'newsletter', icon: Send, cost: 2 },
];

const ContentWriter: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  const { t, locale } = useTranslation();
  const [step, setStep] = useState<'vertical' | 'type' | 'form' | 'result'>('vertical');
  const [selectedVertical, setSelectedVertical] = useState<ContentVertical>('general');
  const [selectedType, setSelectedType] = useState<ContentType>('product_description');
  const [isGenerating, setIsGenerating] = useState(false);
  const [result, setResult] = useState<GeneratedContent | null>(null);
  const [copied, setCopied] = useState(false);

  // Form
  const [brandName, setBrandName] = useState('');
  const [brandUrl, setBrandUrl] = useState('');
  const [productOrService, setProductOrService] = useState('');
  const [targetAudience, setTargetAudience] = useState('');
  const [tone, setTone] = useState<ContentWriterInput['tone']>('professionnel');
  const [language, setLanguage] = useState<'fr' | 'en' | 'es'>(locale as 'fr' | 'en' | 'es');
  const [additionalContext, setAdditionalContext] = useState('');

  const currentTypeCost = CONTENT_TYPE_ICONS.find(ct => ct.id === selectedType)?.cost || 2;

  // Get translated labels
  const getVerticalLabel = (id: ContentVertical) => t.contentWriter.verticals[id] || id;
  const getContentTypeLabel = (id: ContentType) => t.contentWriter.contentTypes[id] || id;
  const getToneLabel = (id: string) => t.contentWriter.tones[id] || id;

  const handleGenerate = async () => {
    if (!brandName || !productOrService || !targetAudience) {
      alert(locale === 'en' ? 'Please fill in all required fields.' : locale === 'es' ? 'Por favor, rellena todos los campos obligatorios.' : 'Veuillez remplir tous les champs obligatoires.');
      return;
    }

    const canProceed = onDeductCredits(currentTypeCost);
    if (!canProceed) return;

    setIsGenerating(true);
    try {
      const output = await generateContent({
        vertical: selectedVertical,
        contentType: selectedType,
        brandName,
        brandUrl: brandUrl || undefined,
        productOrService,
        targetAudience,
        tone,
        language,
        additionalContext: additionalContext || undefined,
      });
      setResult(output);
      setStep('result');
    } catch (error) {
      console.error(error);
      alert(locale === 'en' ? 'Generation error.' : locale === 'es' ? 'Error de generacion.' : 'Erreur lors de la generation.');
    } finally {
      setIsGenerating(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = (filename: string, content: string) => {
    const blob = new Blob([content], { type: 'text/markdown' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleRegenerate = () => {
    setResult(null);
    setStep('form');
  };

  const ScoreRingMini = ({ score }: { score: number }) => {
    const color = score >= 75 ? '#a855f7' : score >= 50 ? '#c084fc' : '#ef4444';
    const circumference = 2 * Math.PI * 28;
    const offset = circumference - (score / 100) * circumference;
    return (
      <div className="relative w-20 h-20">
        <svg className="w-20 h-20 -rotate-90" viewBox="0 0 64 64">
          <circle cx="32" cy="32" r="28" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="4" />
          <circle cx="32" cy="32" r="28" fill="none" stroke={color} strokeWidth="4" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
        </svg>
        <div className="absolute inset-0 flex items-center justify-center">
          <span className="text-lg font-bold text-white">{score}</span>
        </div>
      </div>
    );
  };

  return (
    <div className="w-full px-4 py-10 animate-in fade-in duration-500 min-h-screen">
      <button onClick={onBack} className="flex items-center text-gray-500 hover:text-white mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" /> {t.common.back}
      </button>

      {/* Header */}
      <div className="flex items-center gap-4 mb-10">
        <div className="p-3 bg-rose-500/10 rounded-2xl">
          <Feather size={32} className="text-rose-400" />
        </div>
        <div>
          <h1 className="text-3xl font-bold text-white">{t.contentWriter.title}</h1>
          <p className="text-gray-500">{t.contentWriter.subtitle}</p>
        </div>
        <span className="ml-auto bg-rose-500/10 text-rose-400 text-xs font-bold px-3 py-1 rounded-full border border-rose-500/20 flex items-center gap-1">
          <Sparkles size={12} /> {t.contentWriter.framework}
        </span>
      </div>

      {/* Step 1: Select Vertical */}
      {step === 'vertical' && (
        <div>
          <h2 className="text-xl font-bold text-white mb-6">1. {t.contentWriter.step1Title}</h2>
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
            {VERTICAL_ICONS.map(v => (
              <button
                key={v.id}
                onClick={() => { setSelectedVertical(v.id); setStep('type'); }}
                className="ninja-card p-6 flex flex-col items-center gap-3 hover:bg-white/[0.04] hover:border-white/[0.12] transition-all group"
              >
                <v.icon size={32} className={`${v.color} group-hover:scale-110 transition-transform`} />
                <span className="text-sm font-bold text-gray-300 group-hover:text-white">{getVerticalLabel(v.id)}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Step 2: Select Content Type */}
      {step === 'type' && (
        <div>
          <div className="flex items-center gap-2 mb-2">
            <button onClick={() => setStep('vertical')} className="text-gray-500 hover:text-white text-sm">&larr; Vertical</button>
            <span className="text-gray-600 text-sm">/</span>
            <span className="text-rose-400 text-sm font-medium">{getVerticalLabel(selectedVertical)}</span>
          </div>
          <h2 className="text-xl font-bold text-white mb-6">2. {t.contentWriter.step2Title}</h2>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
            {CONTENT_TYPE_ICONS.map(ct => (
              <button
                key={ct.id}
                onClick={() => { setSelectedType(ct.id); setStep('form'); }}
                className="ninja-card p-5 flex flex-col items-center gap-3 hover:bg-white/[0.04] hover:border-white/[0.12] transition-all group"
              >
                <ct.icon size={28} className="text-rose-400 group-hover:scale-110 transition-transform" />
                <span className="text-xs font-bold text-gray-300 group-hover:text-white text-center">{getContentTypeLabel(ct.id)}</span>
                <span className="text-[10px] text-gray-500">{ct.cost} {t.common.credits}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Step 3: Form */}
      {step === 'form' && (
        <div>
          <div className="flex items-center gap-2 mb-2">
            <button onClick={() => setStep('type')} className="text-gray-500 hover:text-white text-sm">&larr; Type</button>
            <span className="text-gray-600 text-sm">/</span>
            <span className="text-rose-400 text-sm font-medium">{getContentTypeLabel(selectedType)}</span>
          </div>
          <h2 className="text-xl font-bold text-white mb-6">3. {t.contentWriter.step3Title}</h2>
          <div className="ninja-card p-6 space-y-5">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              <div>
                <label className="block text-sm text-gray-500 mb-1.5">{t.contentWriter.brandName} *</label>
                <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-[#111111] border border-white/[0.08] rounded-2xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              </div>
              <div>
                <label className="block text-sm text-gray-500 mb-1.5">{t.contentWriter.brandUrl} ({t.common.optional})</label>
                <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-[#111111] border border-white/[0.08] rounded-2xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              </div>
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.contentWriter.productOrService} *</label>
              <input value={productOrService} onChange={e => setProductOrService(e.target.value)} placeholder="Ex: AEO optimization platform" className="w-full bg-[#111111] border border-white/[0.08] rounded-2xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.contentWriter.targetAudience} *</label>
              <input value={targetAudience} onChange={e => setTargetAudience(e.target.value)} placeholder="Ex: B2B Marketing Directors" className="w-full bg-[#111111] border border-white/[0.08] rounded-2xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
              <div>
                <label className="block text-sm text-gray-500 mb-1.5">{t.contentWriter.tone}</label>
                <select value={tone} onChange={e => setTone(e.target.value as any)} className="w-full bg-[#111111] border border-white/[0.08] rounded-2xl p-3 text-white focus:border-purple-500/50 outline-none text-sm">
                  {['professionnel', 'decontracte', 'autoritaire', 'empathique', 'technique'].map(toneId => (
                    <option key={toneId} value={toneId}>{getToneLabel(toneId)}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-sm text-gray-500 mb-1.5">{t.contentWriter.language}</label>
                <select value={language} onChange={e => setLanguage(e.target.value as 'fr' | 'en' | 'es')} className="w-full bg-[#111111] border border-white/[0.08] rounded-2xl p-3 text-white focus:border-purple-500/50 outline-none text-sm">
                  <option value="fr">{t.contentWriter.contentLanguages.fr}</option>
                  <option value="en">{t.contentWriter.contentLanguages.en}</option>
                  <option value="es">{t.contentWriter.contentLanguages.es}</option>
                </select>
              </div>
              <div className="flex items-end">
                <div className="bg-rose-500/10 border border-rose-500/20 rounded-2xl px-4 py-3 text-center w-full">
                  <span className="text-xs text-gray-500">{t.common.score}</span>
                  <span className="block text-lg font-bold text-rose-400">{currentTypeCost} GTO</span>
                </div>
              </div>
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.contentWriter.additionalContext} ({t.common.optional})</label>
              <textarea value={additionalContext} onChange={e => setAdditionalContext(e.target.value)} rows={3} placeholder="..." className="w-full bg-[#111111] border border-white/[0.08] rounded-2xl p-3 text-white focus:border-purple-500/50 outline-none text-sm resize-none" />
            </div>
            <button
              onClick={handleGenerate}
              disabled={isGenerating || !brandName || !productOrService || !targetAudience}
              className="w-full btn-gradient text-white font-bold py-3.5 rounded-full hover:opacity-90 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isGenerating ? <><Loader2 size={18} className="animate-spin" /> {t.common.loading}</> : <><Feather size={18} /> {t.contentWriter.generateContent}</>}
            </button>
          </div>
        </div>
      )}

      {/* Step 4: Result */}
      {step === 'result' && result && (
        <div>
          <div className="flex items-center gap-2 mb-6">
            <button onClick={handleRegenerate} className="text-gray-500 hover:text-white text-sm">&larr; {t.contentWriter.modifyBrief}</button>
          </div>

          {/* Score + Meta */}
          <div className="flex items-center gap-6 mb-8 ninja-card p-6">
            <ScoreRingMini score={result.aeoScore} />
            <div className="flex-1">
              <h3 className="text-lg font-bold text-white">{result.title}</h3>
              {result.metaDescription && <p className="text-sm text-gray-500 mt-1">{result.metaDescription}</p>}
            </div>
            <div className="flex gap-2">
              <button onClick={() => handleCopy(result.content)} className="p-2.5 border border-white/[0.08] bg-white/[0.04] rounded-full hover:bg-white/[0.08] transition-colors" title={t.common.copy}>
                {copied ? <Check size={16} className="text-purple-300" /> : <Copy size={16} className="text-gray-500" />}
              </button>
              <button onClick={() => handleDownload(`${brandName}-${selectedType}.md`, result.content)} className="p-2.5 border border-white/[0.08] bg-white/[0.04] rounded-full hover:bg-white/[0.08] transition-colors" title={t.common.download}>
                <Download size={16} className="text-gray-500" />
              </button>
              <button onClick={handleRegenerate} className="p-2.5 border border-white/[0.08] bg-white/[0.04] rounded-full hover:bg-white/[0.08] transition-colors" title={t.common.regenerate}>
                <RefreshCw size={16} className="text-gray-500" />
              </button>
            </div>
          </div>

          {/* AEO Tips */}
          {result.aeoTips.length > 0 && (
            <div className="mb-6 ninja-card p-5">
              <h4 className="text-sm font-bold text-rose-400 mb-3">{t.contentWriter.aeoTips}</h4>
              <ul className="space-y-1.5">
                {result.aeoTips.map((tip, i) => (
                  <li key={i} className="text-sm text-gray-300 flex items-start gap-2">
                    <span className="text-rose-400 mt-0.5">&#x2022;</span> {tip}
                  </li>
                ))}
              </ul>
            </div>
          )}

          {/* Content */}
          <div className="ninja-card p-6">
            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 leading-relaxed">
              {result.content}
            </div>
          </div>

          {/* Schema Markup */}
          {result.schemaMarkup && (
            <div className="mt-6 ninja-card p-6">
              <div className="flex items-center justify-between mb-3">
                <h4 className="text-sm font-bold text-gray-200">{t.contentWriter.schemaJsonLd}</h4>
                <button onClick={() => handleCopy(result.schemaMarkup || '')} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
                  <Copy size={12} /> {t.common.copy}
                </button>
              </div>
              <pre className="text-xs text-purple-300 bg-black/40 rounded-xl p-4 overflow-x-auto">{result.schemaMarkup}</pre>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default ContentWriter;
"}

{"content":"import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ContentWriterInput, GeneratedContent, ContentType, ContentVertical } from '../types';

const getApiKey = () => {
  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
    return process.env.API_KEY;
  }
  return null;
};

// PROMPTS SYSTEME PAR TYPE DE CONTENU
export const CONTENT_WRITER_PROMPTS: Record<ContentType, string> = {

  product_description: `# ROLE\nTu es un Expert Copywriter E-commerce & Specialiste AEO (Answer Engine Optimization).\nTu rediges des descriptions produits qui convertissent ET qui sont concues pour etre citees par les IA (ChatGPT, Perplexity, Claude).\n\n# FRAMEWORK C.I.T.E.D.B.Y. A APPLIQUER\n- **C**lear Structure : Hierarchie H1 > H2 > H3, paragraphes < 100 mots\n- **I**nformation Density : Chaque phrase apporte une donnee concrete (specs, chiffres, comparaisons)\n- **T**echnical Accuracy : Termes techniques precis, pas de fluff marketing\n- **E**xpert Positioning : Ton autoritaire, citations de normes/etudes si pertinent\n- **D**irect Answer : Premiere phrase = reponse directe\n- **B**acklink Worthy : Contenu assez riche pour etre reference\n- **Y**ielding Value : Le lecteur repart avec une info actionnable\n\n# FORMAT DE SORTIE\n1. Titre H1 optimise (nom du produit + benefice principal)\n2. Accroche (2 phrases max — LA phrase que les IA extrairont)\n3. Description longue (300-500 mots, structuree en H2/H3)\n4. Specifications (format tableau Markdown)\n5. FAQ Produit (3-5 questions/reponses de 40-60 mots)\n6. Meta Description (150-160 caracteres)\n7. Schema.org Product (JSON-LD complet)\n\n# REGLES\n- Commence TOUJOURS par une definition directe du produit\n- Integre des donnees chiffrees\n- Utilise des comparaisons concretes\n- Chaque H2 formule comme une question\n- FAQ reponses : 40-60 mots, reponse directe`,

  landing_page: `# ROLE\nTu es un Growth Copywriter Senior specialise en Landing Pages a haute conversion, expert AEO.\n\n# FORMAT DE SORTIE OBLIGATOIRE\n\n## SECTION 1 : HERO\n- Headline H1 : Benefice principal + mot-cle cible (max 10 mots)\n- Sous-titre : Developpe le H1 en 1 phrase (max 25 mots)\n- CTA Principal : Texte du bouton + texte de reassurance\n- Social Proof rapide\n\n## SECTION 2 : PROBLEME / AGITATION\n- H2 Question\n- 3 pain points avec titre + description\n\n## SECTION 3 : SOLUTION\n- H2 : Comment le produit resout le probleme\n- 3-4 features avec benefice mesurable\n\n## SECTION 4 : PREUVES\n- Temoignage client template\n- Chiffres cles (3 metriques)\n\n## SECTION 5 : FAQ\n- 5 questions/reponses (40-60 mots)\n- Format Answer-First obligatoire\n\n## SECTION 6 : CTA FINAL\n- Reformulation du benefice + CTA + garantie\n\n## EXTRAS\n- Meta Description, Schema.org WebPage JSON-LD, Open Graph tags\n\n# REGLES\n- Chaque section auto-suffisante (extractible par IA)\n- Aucune phrase > 25 mots\n- Donnees chiffrees dans chaque section`,

  sales_email: `# ROLE\nTu es un Expert en Cold Emailing B2B & Specialiste en copywriting de conversion.\n\n# MISSION\nGenere une SEQUENCE de 3 emails de prospection (Cold, Follow-up, Break-up).\n\n# FORMAT DE SORTIE\n\n## EMAIL 1 : PREMIER CONTACT\n- Objet : Court (< 6 mots), personnalise\n- Ligne 1 : Personnalisation\n- Ligne 2-3 : Probleme + impact chiffre\n- Ligne 4 : Solution en 1 phrase\n- Ligne 5 : Preuve sociale\n- CTA : Question ouverte\n\n## EMAIL 2 : FOLLOW-UP (J+3)\n- Objet : Re: ou reference au premier email\n- Corps : Nouvel angle (etude de cas, stat)\n- CTA : Plus direct\n\n## EMAIL 3 : BREAK-UP (J+7)\n- Objet : Derniere question\n- Corps : Court (3-4 lignes), leger\n- CTA : Est-ce que le probleme n est plus une priorite ?\n\n# REGLES\n- Aucun email > 150 mots\n- Pas de J espere que vous allez bien\n- Variables {prenom}, {entreprise}, {secteur}`,

  meta_tags: `# ROLE\nTu es un Specialiste SEO/AEO expert en optimisation de balises meta.\n\n# FORMAT DE SORTIE\n\n## 1. BALISES META ESSENTIELLES\ntitle, description, robots, canonical\n\n## 2. OPEN GRAPH (Facebook/LinkedIn)\nog:title, og:description, og:type, og:url, og:image\n\n## 3. TWITTER CARDS\ntwitter:card, twitter:title, twitter:description\n\n## 4. SCHEMA.ORG (JSON-LD)\n\n## 5. VARIANTES DE TITRES (A/B Testing)\n- Option A : Focus benefice\n- Option B : Focus mot-cle\n- Option C : Focus question\n\n## 6. TIPS AEO\n- Pourquoi ce titre sera extrait par les IA\n- Ameliorations recommandees\n\n# REGLES\n- Title tag : 50-60 caracteres, mot-cle en premier\n- Meta description : 150-160 caracteres, inclure un CTA\n- Pas de keyword stuffing`,

  social_post: `# ROLE\nTu es un Social Media Manager Senior specialise en contenu B2B a forte valeur ajoutee.\n\n# FORMAT DE SORTIE\n\n## POST LINKEDIN (1300-1500 caracteres)\n- Hook : Stat choc OU question provocante\n- Corps : Storytelling en 5-7 phrases courtes\n- Preuve : 1 donnee chiffree\n- CTA : Question ouverte\n- Hashtags : 3-5\n\n## POST TWITTER/X (280 caracteres)\n- Version courte et percutante\n- 1-2 hashtags max\n\n## LEGENDE INSTAGRAM (< 2200 caracteres)\n- Hook visuel\n- Contenu educatif en 3-5 bullet points\n- CTA : Enregistre ce post\n- 15-20 hashtags en commentaire\n\n## SUGGESTION IMAGE/VISUEL\n- Description du visuel ideal\n- Texte overlay suggere\n\n# REGLES\n- Le hook doit arreter le scroll\n- 1 seule idee par post\n- Donnees chiffrees obligatoires\n- Max 3 emojis par post`,

  press_release: `# ROLE\nTu es un Expert Relations Presse & Communication Corporate, specialiste AEO.\n\n# FORMAT DE SORTIE (Structure pyramide inversee)\n\n## EN-TETE\nCOMMUNIQUE DE PRESSE | Date | Diffusion immediate\n\n## TITRE (H1)\n[Qui] + [Quoi] + [Impact] — max 15 mots\n\n## SOUS-TITRE\n1 phrase avec chiffre cle\n\n## PARAGRAPHE 1 : LE LEAD\n3-4 phrases, toutes les infos essentielles. C EST CE QUE LES IA EXTRAIRONT.\n\n## PARAGRAPHE 2 : DEVELOPPEMENT\nContexte, citation du dirigeant, donnees chiffrees\n\n## PARAGRAPHE 3 : PREUVES\nResultats concrets, temoignage\n\n## PARAGRAPHE 4 : PERSPECTIVES\nProchaines etapes\n\n## A PROPOS DE [ENTREPRISE]\nBoilerplate 50-80 mots\n\n## CONTACT PRESSE\nNom | Fonction | Email | Telephone\n\n# REGLES\n- Ton factuel, pas promotionnel\n- Chiffres obligatoires\n- Max 500 mots`,

  case_study: `# ROLE\nTu es un Content Strategist B2B expert en etudes de cas a haute conversion et optimisees AEO.\n\n# FORMAT DE SORTIE\n\n## EN-TETE\nTitre : [Client] augmente [metrique] de [X%] grace a [Solution]\nResume executif : 3 phrases (Probleme, Solution, Resultat) — SNIPPET IA\n\n## SECTION 1 : LE CLIENT\nNom, secteur, taille, localisation, contexte\n\n## SECTION 2 : LE DEFI\nH2 question, 3 pain points chiffres, citation client\n\n## SECTION 3 : LA SOLUTION\nDeploiement, timeline, fonctionnalites cles\n\n## SECTION 4 : LES RESULTATS\nTableau KPIs Avant/Apres/Variation, 3 resultats phares, citation client, ROI\n\n## SECTION 5 : ENSEIGNEMENTS\n3 lecons, conseil\n\n## CTA + SCHEMA.ORG\n\n# REGLES\n- Resultats chiffres OBLIGATOIRES\n- Au moins 2 citations client\n- Max 800 mots\n- Chaque section extractible comme reponse autonome`,

  newsletter: `# ROLE\nTu es un Email Marketing Expert specialise en newsletters B2B a haute valeur ajoutee.\n\n# FORMAT DE SORTIE\n\n## OBJET DE L EMAIL\n- Version A : Curiosite/Question\n- Version B : Benefice direct\n- Version C : Chiffre + Impact\n- Preview text : 40-90 caracteres\n\n## STRUCTURE DU CORPS\n\n### ACCROCHE (2-3 lignes)\nHook personnel ou stat\n\n### SECTION PRINCIPALE (200-300 mots)\nH2 Question, reponse directe, developpement avec donnees, exemple concret, takeaway\n\n### 3 CHOSES A RETENIR\n1 phrase chacune\n\n### CTA PRINCIPAL\nTexte du bouton + contexte\n\n### FOOTER\nPS: teaser du prochain numero\n\n# REGLES\n- Objet : < 50 caracteres\n- Corps : max 500 mots\n- 1 seul CTA principal\n- Ton : collegue expert, pas marque corporate`
};

// PROMPTS PAR VERTICAL METIER
export const VERTICAL_CONTEXT: Record<ContentVertical, string> = {
  ecommerce: `CONTEXTE VERTICAL E-COMMERCE :\n- Vocabulaire : conversion, panier moyen, taux de rebond, fiche produit, marketplace\n- KPIs : taux de conversion, CA, retours, satisfaction\n- Ton : oriente benefice client, urgence subtile, confiance\n- Sources types : etudes Shopify, Statista E-commerce, FEVAD\n- Format prefere : listes de benefices, tableaux comparatifs, FAQ acheteur`,
  saas: `CONTEXTE VERTICAL SAAS :\n- Vocabulaire : MRR, ARR, churn, onboarding, feature, integration, API, scalabilite\n- KPIs : ROI, temps gagne, reduction couts, adoption utilisateur\n- Ton : technique mais accessible, focus valeur business\n- Sources types : rapports Gartner, G2, Capterra\n- Format prefere : comparaisons avant/apres, workflows, demo chiffree`,
